  // -----------------------
  app.get("/api/alunos", async (req: Request, res: Response) => {
    // Coordenador de Curso: filtrar apenas alunos do seu curso
    let coordCursoId: string | null = null;
    const authHeader = req.headers.authorization;
    if (authHeader?.startsWith('Bearer ')) {
      const tok = verifyToken(authHeader.slice(7));
      if (tok?.role === 'coordenador_curso' && tok.cursoId) {
        coordCursoId = tok.cursoId;
      }
    }
    const rows = await query<JsonObject>(
      coordCursoId
        ? `SELECT a.* FROM public.alunos a
           JOIN public.turmas t ON a."turmaId" = t.id
           WHERE t."cursoId" = $1
           ORDER BY a."createdAt" DESC`
        : `SELECT * FROM public.alunos ORDER BY "createdAt" DESC`,
      coordCursoId ? [coordCursoId] : [],
    );
    json(res, 200, rows);
  });

  app.get("/api/finalistas", requireAuth, async (req: Request, res: Response) => {
    try {
      const { anoLetivo } = req.query as { anoLetivo?: string };

      // Verificar se a escola tem 13ª Classe — a classe terminal depende desta config
      const cfgRows13 = await query<JsonObject>(`SELECT "temDecimaTermeira" FROM public.config_geral LIMIT 1`, []);
      const tem13Finalistas: boolean = (cfgRows13[0] as any)?.temDecimaTermeira !== false;

      // Quando 13ª está desactivada, a classe terminal passa a ser a 12ª
      const terminalClasses = tem13Finalistas
        ? ["13ª Classe", "13a Classe", "13ª", "13a"]
        : ["12ª Classe", "12a Classe", "12ª", "12a"];
      const classFilter = terminalClasses.map((_, i) => `t.classe = $${i + 1}`).join(" OR ");

      const rows = await query<JsonObject>(
        `SELECT
          a.id,
          a."numeroMatricula",
          a.nome,
          a.apelido,
          a."dataNascimento",
          a.genero,
          a.foto,
          a."turmaId",
          a."nomePai",
          a."nomeMae",
          a."nomeEncarregado",
          a."telefoneEncarregado",
          a."emailEncarregado",
          a.ativo,
          a."createdAt",
          t.nome AS "turmaNome",
          t.classe,
          t.turno,
          t."anoLetivo",
          t."cursoId",
          c.nome AS "cursoNome",
          c.codigo AS "cursoCodigo",
          c."areaFormacao"
        FROM public.alunos a
        JOIN public.turmas t ON a."turmaId" = t.id
        LEFT JOIN public.cursos c ON t."cursoId" = c.id
        WHERE (${classFilter})
          AND a.ativo = true
          ${anoLetivo ? `AND t."anoLetivo" = $${terminalClasses.length + 1}` : ""}
        ORDER BY c.nome ASC, t.nome ASC, a.nome ASC, a.apelido ASC`,
        anoLetivo ? [...terminalClasses, anoLetivo] : terminalClasses,
      );

      const grouped: Record<string, { cursoId: string | null; cursoNome: string; cursoCodigo: string; areaFormacao: string; alunos: JsonObject[] }> = {};
      for (const row of rows) {
        const key = (row.cursoNome as string) || "Sem Curso";
        if (!grouped[key]) {
          grouped[key] = {
            cursoId: row.cursoId as string | null,
            cursoNome: (row.cursoNome as string) || "Sem Curso",
            cursoCodigo: (row.cursoCodigo as string) || "",
            areaFormacao: (row.areaFormacao as string) || "",
            alunos: [],
          };
        }
        grouped[key].alunos.push(row);
      }

      const grupos = Object.values(grouped).sort((a, b) => a.cursoNome.localeCompare(b.cursoNome));

      json(res, 200, {
        total: rows.length,
        grupos,
      });
    } catch (e) {
      json(res, 500, { error: (e as Error).message });
    }
  });

  // GET /api/alunos/busca?q=... — pesquisa por nome, matrícula ou BI
  app.get("/api/alunos/busca", requireAuth, async (req: Request, res: Response) => {
    const q = String(req.query.q || '').trim();
    if (!q || q.length < 2) return json(res, 200, []);
    const like = `%${q}%`;
    try {
      const rows = await query<JsonObject>(
        `SELECT a.id, a.nome, a.apelido, a."numeroMatricula", a."numeroBi", a.genero,
                a."dataNascimento", a.situacao, a.foto,
                a."nomeEncarregado", a."telefoneEncarregado",
                t.nome AS "turmaNome", t.classe AS "turmaClasse", t.turno AS "turmaTurno",
                t."anoLetivo" AS "turmaAnoLetivo", t.nivel AS "turmaNivel"
         FROM public.alunos a
         LEFT JOIN public.turmas t ON t.id = a."turmaId"
         WHERE a.nome ILIKE $1
            OR a.apelido ILIKE $1
            OR (a.nome || ' ' || a.apelido) ILIKE $1
            OR a."numeroMatricula" ILIKE $1
            OR a."numeroBi" ILIKE $1
         ORDER BY a.nome, a.apelido
         LIMIT 30`,
        [like]
      );
      return json(res, 200, rows);
    } catch (e) {
      return json(res, 500, { error: (e as Error).message });
    }
  });

