  // PATCH approve/reject a lesson plan
  app.patch("/api/planos-aula/:id/status", requireAuth, async (req: Request, res: Response) => {
    try {
      const rolesPermitidas = ['chefe_secretaria', 'admin', 'director', 'ceo', 'pca', 'secretaria', 'professor', 'director_turma'];
      const role = req.jwtUser?.role || '';
      if (!rolesPermitidas.includes(role)) return json(res, 403, { error: 'Sem permissão.' });
      const { id } = req.params;
      const b = requireBodyObject(req) as any;
      const status = b.status as string;
      if (!['aprovado', 'rejeitado', 'rascunho', 'submetido'].includes(status))
        return json(res, 400, { error: 'Status inválido.' });
      const rows = await query<JsonObject>(
        `UPDATE public.planos_aula SET
           status=$1,
           "observacaoDirector"=COALESCE($2,"observacaoDirector"),
           "aprovadoPor"=CASE WHEN $1 IN ('aprovado','rejeitado') THEN $3 ELSE "aprovadoPor" END,
           "aprovadoEm"=CASE WHEN $1 IN ('aprovado','rejeitado') THEN NOW()::text ELSE "aprovadoEm" END,
           "updatedAt"=NOW()
         WHERE id=$4 RETURNING *`,
        [status, b.observacaoDirector ?? null, b.aprovadoPor ?? null, id],
      );
      if (!rows[0]) return json(res, 404, { error: 'Plano não encontrado.' });
      const plano = rows[0] as any;
      // Notificar o professor quando o plano é aprovado ou rejeitado
      if (status === 'aprovado' || status === 'rejeitado') {
        try {
          const profRows = await query<JsonObject>(
            `SELECT "utilizadorId" FROM public.professores WHERE id=$1`,
            [plano.professorId],
          );
          const utilizadorId = profRows[0]?.utilizadorId as string | undefined;
          if (utilizadorId) {
            const obs = (b.observacaoDirector as string | undefined)?.trim() || '';
            const titulo = status === 'aprovado'
              ? `✅ Plano de Aula Aprovado`
              : `❌ Plano de Aula Devolvido`;
            const disciplina = (plano.disciplina as string) || '';
            const turma = (plano.turmaNome as string) || '';
            const mensagem = status === 'aprovado'
              ? `O seu plano de ${disciplina}${turma ? ` (${turma})` : ''} foi aprovado pela direcção pedagógica.${obs ? ` Nota: ${obs}` : ''}`
              : `O seu plano de ${disciplina}${turma ? ` (${turma})` : ''} foi devolvido para revisão. Motivo: ${obs || 'Sem motivo indicado.'}`;
            await query(
              `INSERT INTO public.notificacoes ("utilizadorId","titulo","mensagem","tipo","data","lida","link")
               VALUES ($1,$2,$3,'info',NOW(),false,'/professor-plano-aula')`,
              [utilizadorId, titulo, mensagem],
            );
          }
        } catch (notifErr) {
          console.warn('[planos-aula] Falha ao enviar notificação ao professor:', (notifErr as Error).message);
        }
      }
      return json(res, 200, plano);
    } catch (e) { return json(res, 500, { error: (e as Error).message }); }
  });

