  app.put("/api/professores/:id", requireAuth, requirePermission("professores"), async (req: Request, res: Response) => {
    try {
      const { id } = req.params;
      const b = requireBodyObject(req);

      const allowed = [
        "numeroProfessor",
        "nome",
        "apelido",
        "disciplinas",
        "turmasIds",
        "telefone",
        "email",
        "habilitacoes",
        "ativo",
        "createdAt",
        "nivelEnsino",
        // Payroll fields
        "cargo",
        "categoria",
        "salarioBase",
        "subsidioAlimentacao",
        "subsidioTransporte",
        "subsidioHabitacao",
        "dataContratacao",
        "tipoContrato",
        "valorPorTempoLectivo",
        "temposSemanais",
        "foto",
      ] as const;

      const jsonbKeys = new Set(["disciplinas", "turmasIds"]);
      const setParts: string[] = [];
      const values: unknown[] = [];

      for (const key of allowed) {
        const v = b[key as keyof typeof b];
        if (v === undefined) continue;
        values.push(
          jsonbKeys.has(key) ? jsonbParam(v) : (v as unknown),
        );
        const placeholder = `$${values.length}`;
        setParts.push(
          jsonbKeys.has(key) ? `"${key}" = ${placeholder}::jsonb` : `"${key}" = ${placeholder}`,
        );
      }

      if (setParts.length === 0) {
        return json(res, 400, { error: "No fields to update." });
      }

      const rows = await query<JsonObject>(
        `UPDATE public.professores SET ${setParts.join(", ")} WHERE id = $${values.length + 1} RETURNING *`,
        [...values, id],
      );
      if (!rows[0]) return json(res, 404, { error: "Not found." });

      // Sync foto → utilizadores.avatar for linked user
      if (b.foto !== undefined) {
        try {
          await query(`UPDATE public.utilizadores SET avatar=$1 WHERE id=(SELECT "utilizadorId" FROM public.professores WHERE id=$2)`, [b.foto, id]);
        } catch { /* best-effort */ }
      }

      json(res, 200, rows[0]);
    } catch (e) {
      json(res, 400, { error: (e as Error).message });
    }
  });

  app.delete("/api/professores/:id", requireAuth, requirePermission("professores"), async (req: Request, res: Response) => {
    const { id } = req.params;
    try {
      // Verificar se o professor tem histórico que não pode ser eliminado
      const historico: string[] = [];

      const [horariosR, pautasR, notasR, sumariosR, avaliacoesR] = await Promise.all([
        query<{ n: string }>(`SELECT COUNT(*)::text AS n FROM public.horarios WHERE "professorId"=$1`, [id]),
        query<{ n: string }>(`SELECT COUNT(*)::text AS n FROM public.pautas WHERE "professorId"=$1`, [id]),
        query<{ n: string }>(`SELECT COUNT(*)::text AS n FROM public.notas WHERE "professorId"=$1`, [id]),
        query<{ n: string }>(`SELECT COUNT(*)::text AS n FROM public.sumarios WHERE "professorId"=$1`, [id]),
        query<{ n: string }>(`SELECT COUNT(*)::text AS n FROM public.avaliacoes_parciais WHERE "avaliadorId"=$1`, [id]).catch(() => [{ n: "0" }]),
      ]);

      if (parseInt(horariosR[0]?.n || "0") > 0) historico.push(`${horariosR[0].n} horário(s) atribuído(s)`);
      if (parseInt(pautasR[0]?.n || "0") > 0) historico.push(`${pautasR[0].n} pauta(s) lançada(s)`);
      if (parseInt(notasR[0]?.n || "0") > 0) historico.push(`${notasR[0].n} nota(s) lançada(s)`);
      if (parseInt(sumariosR[0]?.n || "0") > 0) historico.push(`${sumariosR[0].n} sumário(s) registado(s)`);
      if (parseInt(avaliacoesR[0]?.n || "0") > 0) historico.push(`${avaliacoesR[0].n} avaliação(ões) parcial(ais)`);

      if (historico.length > 0) {
        return json(res, 409, {
          error: `Não é possível eliminar este professor porque tem histórico no sistema: ${historico.join(", ")}. Para remover o acesso, inative o professor em vez de o eliminar.`,
          historico,
          sugestao: "inativar",
        });
      }

      const rows = await query<JsonObject>(
        `DELETE FROM public.professores WHERE id = $1 RETURNING *`,
        [id],
      );
      if (!rows[0]) return json(res, 404, { error: "Not found." });
      json(res, 200, rows[0]);
    } catch (e) {
      json(res, 500, { error: (e as Error).message });
    }
  });

  // PATCH /api/professores/:id/disponibilidade — actualizar disponibilidade semanal do professor
  app.patch("/api/professores/:id/disponibilidade", requireAuth, requirePermission("horario"), async (req: Request, res: Response) => {
    try {
      const user = req.jwtUser!;
      const { id } = req.params;
      const { diasDisponiveis, turno } = req.body as { diasDisponiveis?: number[]; turno?: string };
      if (!Array.isArray(diasDisponiveis) || diasDisponiveis.length === 0) {
        return json(res, 400, { error: 'diasDisponiveis deve ser um array não vazio.' });
      }
      // Professores apenas podem actualizar a sua própria disponibilidade
      if (user.role === 'professor') {
        const profRows = await query<JsonObject>(
          `SELECT id FROM public.professores WHERE "utilizadorId" = $1 LIMIT 1`, [user.userId]
        );
        const myProfId = (profRows[0] as any)?.id;
        if (!myProfId || myProfId !== id) {
          return json(res, 403, { error: 'Só pode actualizar a sua própria disponibilidade.' });
        }
      }
      const turnoValido = ['Manhã', 'Tarde', 'Noite', 'Ambos'].includes(turno ?? '') ? turno : 'Ambos';
      const disponibilidade = { diasDisponiveis, turno: turnoValido };
      const rows = await query<JsonObject>(
        `UPDATE public.professores SET disponibilidade = $1::jsonb WHERE id = $2
         RETURNING id, nome, apelido, disponibilidade`,
        [JSON.stringify(disponibilidade), id]
      );
      if (!rows.length) return json(res, 404, { error: 'Professor não encontrado.' });
      json(res, 200, rows[0]);
    } catch (err) {
      json(res, 500, { error: (err as Error).message });
    }
  });

