  // ANIVERSÁRIOS DE HOJE
  app.get("/api/aniversarios-hoje", requireAuth, async (_req: Request, res: Response) => {
    try {
      const hoje = new Date();
      const mm = String(hoje.getMonth() + 1).padStart(2, '0');
      const dd = String(hoje.getDate()).padStart(2, '0');
      // dataNascimento está em alunos e funcionarios (não em utilizadores)
      const rows = await query<JsonObject>(
        `SELECT u.id, u.nome, u.role, u.avatar,
                COALESCE(u.genero, a.genero, f.genero) AS genero,
                COALESCE(NULLIF(u."dataNascimento",''), a."dataNascimento", f."dataNascimento") AS "dataNascimento"
         FROM public.utilizadores u
         LEFT JOIN public.alunos a ON a."utilizadorId" = u.id
         LEFT JOIN public.funcionarios f ON f."utilizadorId" = u.id
         WHERE u.ativo = true
           AND COALESCE(NULLIF(u."dataNascimento",''), a."dataNascimento", f."dataNascimento") IS NOT NULL
           AND COALESCE(NULLIF(u."dataNascimento",''), a."dataNascimento", f."dataNascimento") != ''
           AND (
             COALESCE(NULLIF(u."dataNascimento",''), a."dataNascimento", f."dataNascimento") LIKE $1
             OR COALESCE(NULLIF(u."dataNascimento",''), a."dataNascimento", f."dataNascimento") LIKE $2
             OR COALESCE(NULLIF(u."dataNascimento",''), a."dataNascimento", f."dataNascimento") LIKE $3
           )`,
        [
          `%-${mm}-${dd}`,   // YYYY-MM-DD
          `${dd}/${mm}/%`,   // DD/MM/YYYY
          `${dd}-${mm}-%`,   // DD-MM-YYYY
        ]
      );
      const anoActual = hoje.getFullYear();
      const result = (rows as any[]).map((u: any) => {
        let idade: number | null = null;
        const raw = String(u.dataNascimento || '').trim();
        const m1 = raw.match(/^(\d{4})[-/]/);
        const m2 = raw.match(/[-/](\d{4})$/);
        const anoNasc = m1 ? parseInt(m1[1]) : m2 ? parseInt(m2[1]) : null;
        if (anoNasc && anoNasc >= 1900 && anoNasc <= anoActual) {
          idade = anoActual - anoNasc;
        }
        return { id: u.id, nome: u.nome, role: u.role, avatar: u.avatar, genero: u.genero ?? null, idade };
      });
      json(res, 200, result);
    } catch (e) {
      console.error('[aniversarios-hoje]', (e as Error).message);
      json(res, 500, { error: 'Erro ao obter aniversários' });
    }
  });

