  // ─── Self-Profile Update (any authenticated user, no special permission) ────
  app.put("/api/perfil", requireAuth, async (req: Request, res: Response) => {
    try {
      const userId = req.jwtUser!.userId;
      const b = requireBodyObject(req);

      // Password change flow
      if (b.senhaNova !== undefined) {
        // Must provide current password to change
        if (!b.senhaAtual) return json(res, 400, { error: "Indique a senha actual para alterar a senha." });
        const rows = await query<JsonObject>(`SELECT senha FROM public.utilizadores WHERE id=$1`, [userId]);
        if (!rows[0]) return json(res, 404, { error: "Utilizador não encontrado." });
        const senhaGuardada = String(rows[0].senha ?? '');
        let senhaValida = false;
        if (senhaGuardada.startsWith('$2b$') || senhaGuardada.startsWith('$2a$')) {
          const bcrypt = await import('bcryptjs');
          senhaValida = await bcrypt.compare(String(b.senhaAtual), senhaGuardada);
        } else {
          senhaValida = senhaGuardada === String(b.senhaAtual);
        }
        if (!senhaValida) return json(res, 401, { error: "Senha actual incorrecta. Tente novamente." });
        const bcrypt = await import('bcryptjs');
        const senhaHash = await bcrypt.hash(String(b.senhaNova), 10);
        await query(`UPDATE public.utilizadores SET senha=$1 WHERE id=$2`, [senhaHash, userId]);
        return json(res, 200, { ok: true, message: "Senha alterada com sucesso." });
      }

      // Regular profile fields
      const allowed = ["nome", "email", "telefone", "avatar"] as const;
      const setParts: string[] = []; const values: unknown[] = [];
      for (const key of allowed) {
        const v = b[key]; if (v === undefined) continue;
        values.push(v); setParts.push(`"${key}" = $${values.length}`);
      }
      if (!setParts.length) return json(res, 400, { error: "Nenhum campo para actualizar." });
      const updated = await query<JsonObject>(
        `UPDATE public.utilizadores SET ${setParts.join(",")} WHERE id=$${values.length+1} RETURNING id,nome,email,telefone,role,escola,ativo,avatar`,
        [...values, userId]
      );
      if (!updated[0]) return json(res, 404, { error: "Utilizador não encontrado." });

      // Sync email/telefone/avatar to linked records (best-effort)
      try {
        if (b.email !== undefined || b.telefone !== undefined) {
          // professor
          const syncParts: string[] = []; const syncVals: unknown[] = [];
          if (b.email !== undefined) { syncVals.push(b.email); syncParts.push(`email=$${syncVals.length}`); }
          if (b.telefone !== undefined) { syncVals.push(b.telefone); syncParts.push(`telefone=$${syncVals.length}`); }
          if (syncParts.length) {
            syncVals.push(userId);
            await query(`UPDATE public.professores SET ${syncParts.join(",")} WHERE "utilizadorId"=$${syncVals.length}`, syncVals);
            await query(`UPDATE public.funcionarios SET ${syncParts.join(",")} WHERE "utilizadorId"=$${syncVals.length}`, syncVals);
          }
        }
        // Sync avatar → only the correct table for this specific user's role
        if (b.avatar !== undefined) {
          const role = (updated[0] as any)?.role;
          if (role === 'professor') {
            await query(`UPDATE public.professores SET foto=$1 WHERE "utilizadorId"=$2`, [b.avatar, userId]);
          } else if (role === 'aluno') {
            await query(`UPDATE public.alunos SET foto=$1 WHERE "utilizadorId"=$2`, [b.avatar, userId]);
          }
          // Other roles (admin, director, etc.) only update utilizadores.avatar — already done above
        }
      } catch { /* sync is best-effort */ }

      json(res, 200, updated[0]);
    } catch (e) { json(res, 400, { error: (e as Error).message }); }
  });

  app.put("/api/utilizadores/:id", requireAuth, async (req: Request, res: Response) => {
    try {
      if (!requireUserManagement(req, res)) return;
      const { id } = req.params;
      const b = requireBodyObject(req);
      const existingRows = await query<JsonObject>(`SELECT id, role FROM public.utilizadores WHERE id=$1 LIMIT 1`, [id]);
      if (!existingRows[0]) return json(res, 404, { error: "Utilizador não encontrado." });
      if (existingRows[0].role === "ceo") {
        return json(res, 403, { error: "A conta CEO não pode ser editada por nenhum utilizador." });
      }
      if (b.role === "ceo") {
        return json(res, 403, { error: "Não é permitido transformar outro utilizador em CEO." });
      }
      // Regra: só 1 director e 1 subdirector pedagógico (pedagogico) activos por escola
      if ((b.role === 'director' || b.role === 'pedagogico') && b.role !== existingRows[0].role) {
        const countRows = await query<{c: string}>(
          `SELECT COUNT(*) as c FROM public.utilizadores WHERE role=$1 AND ativo=true AND id != $2`,
          [b.role, id]
        );
        if (parseInt((countRows[0] as any)?.c ?? '0') >= 1) {
          const label = b.role === 'director' ? 'Director' : 'Subdirector Pedagógico';
          return json(res, 409, { error: `Já existe um perfil de ${label} activo. Só é permitido um por escola.` });
        }
      }
      if (b.senha !== undefined && String(b.senha).trim()) {
        const bcrypt = await import("bcryptjs");
        b.senha = await bcrypt.hash(String(b.senha).trim(), 10);
      }
      const allowed = ["nome","email","senha","role","escola","ativo","alunoId","departamento","cargo","telefone","avatar","genero","cursoId","dataNascimento"] as const;
      const setParts: string[] = []; const values: unknown[] = [];
      for (const key of allowed) {
        const v = b[key]; if (v === undefined) continue;
        values.push(v); setParts.push(`"${key}" = $${values.length}`);
      }
      if (!setParts.length) return json(res, 400, { error: "No fields." });
      const rows = await query<JsonObject>(`UPDATE public.utilizadores SET ${setParts.join(",")} WHERE id=$${values.length+1} RETURNING *`, [...values, id]);
      if (!rows[0]) return json(res, 404, { error: "Not found." });
      const updatedUser = rows[0] as any;
      try {
        const syncParts: string[] = [];
        const syncVals: unknown[] = [];
        if (b.email !== undefined) { syncVals.push(b.email); syncParts.push(`email=$${syncVals.length}`); }
        if (b.telefone !== undefined) { syncVals.push(b.telefone); syncParts.push(`telefone=$${syncVals.length}`); }
        if (b.genero !== undefined) { syncVals.push(b.genero); syncParts.push(`genero=$${syncVals.length}`); }
        if (syncParts.length) {
          syncVals.push(id);
          await query(`UPDATE public.professores SET ${syncParts.join(",")} WHERE "utilizadorId"=$${syncVals.length}`, syncVals);
          await query(`UPDATE public.funcionarios SET ${syncParts.join(",")} WHERE "utilizadorId"=$${syncVals.length}`, syncVals);
          await query(`UPDATE public.alunos SET ${syncParts.join(",")} WHERE "utilizadorId"=$${syncVals.length}`, syncVals);
        }
      } catch (syncErr) {
        console.warn('[utilizadores] sync linked records on update failed:', (syncErr as Error).message);
      }
      // Auto-link aluno record when alunoId is set and role is 'aluno'
      if (updatedUser.role === 'aluno' && updatedUser.alunoId) {
        try {
          await query<JsonObject>(
            `UPDATE public.alunos SET "utilizadorId" = $1 WHERE id = $2`,
            [updatedUser.id, updatedUser.alunoId]
          );
        } catch (alunoErr) {
          console.warn('[utilizadores] auto-link aluno on update failed:', (alunoErr as Error).message);
        }
      }
      // ── Alerta de segurança por email ────────────────────────────────────────
      // Envia email ao utilizador afectado quando o perfil é modificado por outra pessoa
      const requesterId = req.jwtUser!.userId;
      if (requesterId !== id && updatedUser.email) {
        try {
          const cfgRows = await query<{ nomeEscola: string; nome: string }>(`SELECT "nomeEscola", nome FROM public.config_geral LIMIT 1`);
          const nomeEscola = cfgRows[0]?.nomeEscola || 'Super Escola';
          const requesterRows = await query<{ nome: string; email: string; role: string }>(`SELECT nome, email, role FROM public.utilizadores WHERE id=$1 LIMIT 1`, [requesterId]);
          const requesterNome = requesterRows[0]?.nome || req.jwtUser!.email || 'Administrador';
          // Determinar campos visíveis alterados (excluir senha)
          const LABEL_MAP: Record<string, string> = {
            nome: 'Nome', email: 'Email', telefone: 'Telefone', role: 'Papel/Função',
            escola: 'Escola', ativo: 'Estado da conta', genero: 'Género', avatar: 'Foto de perfil',
            departamento: 'Departamento', cargo: 'Cargo', cursoId: 'Curso',
          };
          const camposAlterados = Object.entries(b)
            .filter(([k]) => k !== 'senha' && LABEL_MAP[k])
            .map(([k, v]) => ({
              label: LABEL_MAP[k],
              valor: k === 'ativo' ? (v ? 'Activa' : 'Suspensa') : String(v ?? ''),
            }));
          if (b.senha !== undefined) {
            camposAlterados.push({ label: 'Senha', valor: '(alterada)' });
          }
          sendProfileSecurityAlert(
            String(updatedUser.email),
            String(updatedUser.nome || ''),
            requesterNome,
            camposAlterados,
            nomeEscola
          ).catch(err => console.warn('[security-alert] Falha ao enviar email:', err?.message));
        } catch (alertErr) {
          console.warn('[security-alert] Erro ao preparar email de alerta:', (alertErr as Error).message);
        }
      }

      // ── Notificação de promoção/alteração de perfil de acesso ────────────────
      // Envia email ao utilizador quando o seu ROLE muda (independentemente de quem o alterou)
      if (b.role !== undefined && String(b.role) !== String(existingRows[0].role) && updatedUser.email) {
        try {
          const ROLE_LABELS: Record<string, string> = {
            admin: 'Administrador', director: 'Director', pedagogico: 'Subdirector Pedagógico',
            professor: 'Professor', aluno: 'Aluno', encarregado: 'Encarregado de Educação',
            financeiro: 'Financeiro', secretaria: 'Secretaria', chefe_secretaria: 'Chefe de Secretaria',
            pca: 'Presidente do Conselho de Administração', coordenador_curso: 'Coordenador de Curso',
            bibliotecario: 'Bibliotecário', rh: 'Recursos Humanos', ceo: 'CEO',
          };
          const cfgR = await query<{ nomeEscola: string }>(`SELECT "nomeEscola" FROM public.config_geral LIMIT 1`);
          const nomeEscolaR = cfgR[0]?.nomeEscola || 'Super Escola';
          const novoLabel = ROLE_LABELS[String(b.role)] ?? String(b.role);
          const antigoLabel = ROLE_LABELS[String(existingRows[0].role)] ?? String(existingRows[0].role);
          sendAccessNotificationEmail(
            String(updatedUser.email),
            String(updatedUser.nome || ''),
            'Perfil de acesso actualizado',
            [
              { label: 'Perfil anterior', valor: antigoLabel },
              { label: 'Novo perfil', valor: novoLabel },
              { label: 'Efectuado por', valor: String(requesterRows?.[0]?.nome || 'Administrador') },
            ],
            nomeEscolaR
          ).catch(err => console.warn('[access-notify] role change email failed:', err?.message));
        } catch (roleEmailErr) {
          console.warn('[access-notify] Erro ao notificar mudança de role:', (roleEmailErr as Error).message);
        }
      }

      broadcastChange('utilizadores');
      json(res, 200, updatedUser);
    } catch (e) { json(res, 400, { error: (e as Error).message }); }
  });

  app.delete("/api/utilizadores/:id", requireAuth, async (req: Request, res: Response) => {
    if (!requireUserManagement(req, res)) return;
    const existingRows = await query<JsonObject>(`SELECT id, role FROM public.utilizadores WHERE id=$1 LIMIT 1`, [req.params.id]);
    if (!existingRows[0]) return json(res, 404, { error: "Not found." });
    if (existingRows[0].role === "ceo") {
      return json(res, 403, { error: "A conta CEO não pode ser eliminada por nenhum utilizador." });
    }
    const rows = await query<JsonObject>(`DELETE FROM public.utilizadores WHERE id=$1 RETURNING *`, [req.params.id]);
    if (!rows[0]) return json(res, 404, { error: "Not found." });
    broadcastChange('utilizadores');
    json(res, 200, rows[0]);
  });

  // Helper: verifica unicidade de BI/NIF/telefone/email em funcionarios antes de INSERT/UPDATE
  async function checkFuncionarioDuplicados(
    fields: { bi?: string; nif?: string; telefone?: string; email?: string },
    excludeId?: string
  ): Promise<string | null> {
    const checks: { col: string; val: string; label: string }[] = [
      { col: 'bi',       val: fields.bi       ?? '', label: 'Bilhete de Identidade' },
      { col: 'nif',      val: fields.nif      ?? '', label: 'NIF'                  },
      { col: 'telefone', val: fields.telefone ?? '', label: 'Telefone'              },
      { col: 'email',    val: fields.email    ?? '', label: 'Email'                 },
    ];
    for (const { col, val, label } of checks) {
      if (!val || val.trim() === '') continue;
      const rows = excludeId
        ? await query<JsonObject>(`SELECT id FROM public.funcionarios WHERE "${col}"=$1 AND id<>$2 LIMIT 1`, [val.trim(), excludeId])
        : await query<JsonObject>(`SELECT id FROM public.funcionarios WHERE "${col}"=$1 LIMIT 1`, [val.trim()]);
      if (rows.length > 0) return `Já existe um funcionário registado com este ${label}.`;
    }
    return null;
  }

