  // Listar incidentes (todos OU por professor)
  app.get('/api/incidentes-pauta', requireAuth, async (req: Request, res: Response) => {
    try {
      const { professorId, anoLetivo } = req.query as Record<string, string>;
      const conds: string[] = []; const params: unknown[] = [];
      if (professorId) { params.push(professorId); conds.push(`"professorId"=$${params.length}`); }
      if (anoLetivo)   { params.push(anoLetivo);   conds.push(`"anoLetivo"=$${params.length}`); }
      const where = conds.length ? `WHERE ${conds.join(' AND ')}` : '';
      const rows = await query<JsonObject>(
        `SELECT * FROM public.incidentes_pauta ${where} ORDER BY "criadoEm" DESC LIMIT 500`,
        params
      );
      json(res, 200, rows);
    } catch (e) { json(res, 500, { error: (e as Error).message }); }
  });

  // Histórico de pautas de um professor
  app.get('/api/pautas/professor/:id/historico', requireAuth, async (req: Request, res: Response) => {
    try {
      const rows = await query<JsonObject>(
        `SELECT p.*, t.nome AS "turmaNome"
         FROM public.pautas p LEFT JOIN public.turmas t ON t.id = p."turmaId"
         WHERE p."professorId"=$1
         ORDER BY p."anoLetivo" DESC, p.trimestre DESC, p."createdAt" DESC
         LIMIT 60`,
        [req.params.id]
      );
      const incidentes = await query<JsonObject>(
        `SELECT * FROM public.incidentes_pauta WHERE "professorId"=$1 ORDER BY "criadoEm" DESC LIMIT 50`,
        [req.params.id]
      );
      json(res, 200, { pautas: rows, incidentes });
    } catch (e) { json(res, 500, { error: (e as Error).message }); }
  });

  // -----------------------
  // DESEMPENHO DE PROFESSORES (cumprimento de prazos de pautas)
  // -----------------------
  app.get('/api/professores/desempenho-prazos', requireAuth, async (req: Request, res: Response) => {
    try {
      const { anoLetivo, trimestre } = req.query as Record<string, string>;

      // 1. Buscar professores activos
      const professores = await query<any>(`SELECT id, nome, apelido, "numeroProfessor", disciplinas FROM public.professores WHERE ativo=true ORDER BY nome`, []);

      // 2. Buscar prazos definidos (para saber qual era o deadline de cada trimestre)
      let prazosSql = `SELECT * FROM public.prazos_mini_pauta WHERE ativo=true`;
      const prazosParams: unknown[] = [];
      if (anoLetivo) { prazosParams.push(anoLetivo); prazosSql += ` AND "anoLetivo"=$${prazosParams.length}`; }
      if (trimestre) { prazosParams.push(Number(trimestre)); prazosSql += ` AND trimestre=$${prazosParams.length}`; }
      prazosSql += ` ORDER BY trimestre`;
      const prazos = await query<any>(prazosSql, prazosParams);

      // 3. Buscar todas as pautas (com timestamp de submissão)
      let pautasSql = `SELECT p.*, t.nome AS "turmaNome" FROM public.pautas p LEFT JOIN public.turmas t ON t.id=p."turmaId" WHERE 1=1`;
      const pautasParams: unknown[] = [];
      if (anoLetivo) { pautasParams.push(anoLetivo); pautasSql += ` AND p."anoLetivo"=$${pautasParams.length}`; }
      if (trimestre) { pautasParams.push(Number(trimestre)); pautasSql += ` AND p.trimestre=$${pautasParams.length}`; }
      const pautas = await query<any>(pautasSql, pautasParams);

      // 4. Buscar incidentes de atraso registados
      let incidentesSql = `SELECT * FROM public.incidentes_pauta WHERE tipo IN ('atraso','lancamento_admin') AND 1=1`;
      const incidentesParams: unknown[] = [];
      if (anoLetivo) { incidentesParams.push(anoLetivo); incidentesSql += ` AND "anoLetivo"=$${incidentesParams.length}`; }
      if (trimestre) { incidentesParams.push(Number(trimestre)); incidentesSql += ` AND trimestre=$${incidentesParams.length}`; }
      const incidentes = await query<any>(incidentesSql, incidentesParams);

      // 5. Calcular métricas por professor
      const resultado = professores.map((prof: any) => {
        const pautasProf = pautas.filter((p: any) => p.professorId === prof.id);
        const incidentesProf = incidentes.filter((i: any) => i.professorId === prof.id);

        // Para cada pauta, verificar se foi lançada dentro do prazo
        let noPrazo = 0;
        let comAtraso = 0;
        let pendentes = 0;

        for (const pauta of pautasProf) {
          const prazo = prazos.find((pr: any) => pr.trimestre === pauta.trimestre && (!anoLetivo || pr.anoLetivo === pauta.anoLetivo));
          if (!prazo) { pendentes++; continue; }

          const dataLimite = new Date(prazo.dataLimite + 'T23:59:59');
          const dataFecho = pauta.dataFecho ? new Date(pauta.dataFecho) : null;
          const dataCriacao = new Date(pauta.createdAt);
          const dataRef = dataFecho || dataCriacao;

          if (pauta.status === 'fechada' || pauta.status === 'aberta') {
            if (dataRef <= dataLimite) {
              noPrazo++;
            } else {
              comAtraso++;
            }
          } else {
            pendentes++;
          }
        }

        const totalPautas = pautasProf.length;
        const totalLancadas = noPrazo + comAtraso;
        const txCumprimento = totalLancadas > 0 ? Math.round((noPrazo / totalLancadas) * 100) : (totalPautas === 0 ? 100 : 0);
        const nIncidentes = incidentesProf.length;

        // Score: 100 base - 10 por incidente - penalidade proporcional de atrasos
        const penAtraso = totalLancadas > 0 ? Math.round((comAtraso / totalLancadas) * 40) : 0;
        const score = Math.max(0, Math.min(100, 100 - (nIncidentes * 10) - penAtraso));

        let classificacao = 'Muito Bom';
        if (score >= 90) classificacao = 'Excelente';
        else if (score >= 75) classificacao = 'Muito Bom';
        else if (score >= 60) classificacao = 'Satisfatório';
        else if (score >= 40) classificacao = 'Insuficiente';
        else classificacao = 'Crítico';

        return {
          professorId: prof.id,
          nome: prof.nome,
          apelido: prof.apelido,
          nomeCompleto: `${prof.nome} ${prof.apelido}`.trim(),
          numeroProfessor: prof.numeroProfessor,
          disciplinas: Array.isArray(prof.disciplinas) ? prof.disciplinas : [],
          totalPautas,
          totalLancadas,
          noPrazo,
          comAtraso,
          pendentes,
          taxaCumprimento: txCumprimento,
          nIncidentes,
          score,
          classificacao,
        };
      });

      // Ordenar por score DESC
      resultado.sort((a: any, b: any) => b.score - a.score);

      json(res, 200, {
        professores: resultado,
        prazos,
        anoLetivo: anoLetivo || null,
        trimestre: trimestre ? Number(trimestre) : null,
      });
    } catch (e) { json(res, 500, { error: (e as Error).message }); }
  });

  // -----------------------
  // PRAZOS MINI-PAUTA
