  // Helper: validar data ISO YYYY-MM-DD e regras
  function validarPrazoMiniPauta(dataLimite: string): { ok: boolean; erro?: string } {
    if (!/^\d{4}-\d{2}-\d{2}$/.test(dataLimite)) return { ok: false, erro: 'Formato de data inválido (use AAAA-MM-DD).' };
    const hoje = new Date(); hoje.setHours(0,0,0,0);
    const d = new Date(dataLimite + 'T00:00:00');
    if (Number.isNaN(d.getTime())) return { ok: false, erro: 'Data inválida.' };
    if (d.getTime() < hoje.getTime()) return { ok: false, erro: 'A data limite não pode estar no passado.' };
    return { ok: true };
  }

  async function registarHistoricoPrazo(
    prazoId: string | null, trimestre: number, anoLetivo: string,
    dataAntiga: string | null, dataNova: string | null,
    acao: 'criado' | 'alterado' | 'eliminado' | 'prorrogado',
    motivo: string | null, alteradoPor: string | null
  ) {
    try {
      await query(
        `INSERT INTO public.prazos_mini_pauta_historico
          (id,"prazoId",trimestre,"anoLetivo","dataLimiteAntiga","dataLimiteNova",acao,motivo,"alteradoPor")
         VALUES (gen_random_uuid(),$1,$2,$3,$4,$5,$6,$7,$8)`,
        [prazoId, trimestre, anoLetivo, dataAntiga, dataNova, acao, motivo, alteradoPor]
      );
    } catch (er) { console.warn('[prazo-historico]', (er as Error).message); }
  }

  app.post("/api/prazos-mini-pauta", requireAuth, requirePermission("pautas"), async (req: Request, res: Response) => {
    try {
      const b = requireBodyObject(req);
      const dataLimite = String(b.dataLimite || '');
      const v = validarPrazoMiniPauta(dataLimite);
      if (!v.ok) return json(res, 400, { error: v.erro });
      const existentes = await query<JsonObject>(
        `SELECT * FROM public.prazos_mini_pauta WHERE trimestre=$1 AND "anoLetivo"=$2 LIMIT 1`,
        [b.trimestre, b.anoLetivo]
      );
      const antigo = existentes[0] || null;
      const dataInicio = b.dataInicio ? String(b.dataInicio) : null;
      const rows = await query<JsonObject>(
        `INSERT INTO public.prazos_mini_pauta (id, trimestre, "anoLetivo", "dataInicio", "dataLimite", descricao, ativo, "criadoPor", "gracePeriodHoras", "bloqueioAposPrazo")
         VALUES (gen_random_uuid(), $1, $2, $3, $4, $5, $6, $7, $8, $9)
         ON CONFLICT (trimestre, "anoLetivo") DO UPDATE SET
           "dataInicio" = EXCLUDED."dataInicio",
           "dataLimite" = EXCLUDED."dataLimite",
           descricao = EXCLUDED.descricao,
           ativo = EXCLUDED.ativo,
           "criadoPor" = EXCLUDED."criadoPor",
           "gracePeriodHoras" = EXCLUDED."gracePeriodHoras",
           "bloqueioAposPrazo" = EXCLUDED."bloqueioAposPrazo"
         RETURNING *`,
        [b.trimestre, b.anoLetivo, dataInicio, dataLimite, b.descricao ?? null, b.ativo ?? true,
         b.criadoPor ?? null, Number(b.gracePeriodHoras ?? 0), !!b.bloqueioAposPrazo]
      );
      const novo = rows[0];
      await registarHistoricoPrazo(
        String(novo.id), Number(b.trimestre), String(b.anoLetivo),
        antigo ? String(antigo.dataLimite) : null, dataLimite,
        antigo ? 'alterado' : 'criado',
        b.motivo ? String(b.motivo) : null,
        b.criadoPor ? String(b.criadoPor) : null
      );
      // Auto-fechar pautas de trimestres anteriores ao recém-criado (mesmo ano lectivo)
      // Só fecha pautas dos trimestres ANTERIORES ao que está a ser criado
      const novoTrimestre = Number(b.trimestre);
      const anoLetivo = String(b.anoLetivo);
      if (novoTrimestre > 1) {
        const trimestresFechados = [1, 2, 3].filter(t => t < novoTrimestre);
        for (const tri of trimestresFechados) {
          await query(
            `UPDATE public.pautas SET status='fechada', "dataFecho"=$1
             WHERE "anoLetivo"=$2 AND trimestre=$3 AND status='aberta'`,
            [new Date().toISOString().slice(0, 10), anoLetivo, tri]
          );
        }
      }
      json(res, 201, novo);
    } catch (e) { json(res, 400, { error: (e as Error).message }); }
  });

  app.put("/api/prazos-mini-pauta/:id", requireAuth, requirePermission("pautas"), async (req: Request, res: Response) => {
    try {
      const { id } = req.params;
      const b = requireBodyObject(req);
      const existentes = await query<JsonObject>(`SELECT * FROM public.prazos_mini_pauta WHERE id=$1`, [id]);
      const antigo = existentes[0];
      if (!antigo) return json(res, 404, { error: "Not found." });
      if (b.dataLimite !== undefined) {
        const v = validarPrazoMiniPauta(String(b.dataLimite));
        if (!v.ok) return json(res, 400, { error: v.erro });
      }
      const allowed = ["dataInicio","dataLimite","descricao","ativo","gracePeriodHoras","bloqueioAposPrazo"] as const;
      const setParts: string[] = []; const values: unknown[] = [];
      for (const key of allowed) {
        const v = b[key]; if (v === undefined) continue;
        values.push(v); setParts.push(`"${key}"=$${values.length}`);
      }
      if (!setParts.length) return json(res, 400, { error: "No fields." });
      const rows = await query<JsonObject>(`UPDATE public.prazos_mini_pauta SET ${setParts.join(",")} WHERE id=$${values.length+1} RETURNING *`, [...values, id]);
      if (!rows[0]) return json(res, 404, { error: "Not found." });
      if (b.dataLimite !== undefined && String(b.dataLimite) !== String(antigo.dataLimite)) {
        await registarHistoricoPrazo(
          id, Number(antigo.trimestre), String(antigo.anoLetivo),
          String(antigo.dataLimite), String(b.dataLimite), 'alterado',
          b.motivo ? String(b.motivo) : null,
          b.alteradoPor ? String(b.alteradoPor) : null
        );
      }
      json(res, 200, rows[0]);
    } catch (e) { json(res, 400, { error: (e as Error).message }); }
  });

  // Activar / desactivar o bloqueio de pautas para um prazo específico (reactivação global ou bloqueio)
  app.patch("/api/prazos-mini-pauta/:id/toggle-bloqueio", requireAuth, requirePermission("pautas"), async (req: Request, res: Response) => {
    try {
      const { id } = req.params;
      const b = requireBodyObject(req);
      if (typeof b.bloqueioAposPrazo !== 'boolean') {
        return json(res, 400, { error: 'O campo bloqueioAposPrazo (boolean) é obrigatório.' });
      }
      const rows = await query<JsonObject>(
        `UPDATE public.prazos_mini_pauta SET "bloqueioAposPrazo"=$1 WHERE id=$2 RETURNING *`,
        [b.bloqueioAposPrazo, id]
      );
      if (!rows[0]) return json(res, 404, { error: 'Prazo não encontrado.' });
      const p = rows[0] as any;
      const motivo = b.bloqueioAposPrazo
        ? 'Bloqueio activado — pautas ocultadas para todos os professores.'
        : 'Bloqueio desactivado — pautas reactivadas para todos os professores.';
      await registarHistoricoPrazo(
        String(p.id), Number(p.trimestre), String(p.anoLetivo),
        String(p.dataLimite), String(p.dataLimite),
        'alterado', motivo,
        (req.jwtUser as any)?.nome || null
      );
      json(res, 200, rows[0]);
    } catch (e) { json(res, 500, { error: (e as Error).message }); }
  });

  app.delete("/api/prazos-mini-pauta/:id", requireAuth, requirePermission("pautas"), async (req: Request, res: Response) => {
    const existentes = await query<JsonObject>(`SELECT * FROM public.prazos_mini_pauta WHERE id=$1`, [req.params.id]);
    const antigo = existentes[0];
    const rows = await query<JsonObject>(`DELETE FROM public.prazos_mini_pauta WHERE id=$1 RETURNING *`, [req.params.id]);
    if (!rows[0]) return json(res, 404, { error: "Not found." });
    if (antigo) {
      await registarHistoricoPrazo(
        String(antigo.id), Number(antigo.trimestre), String(antigo.anoLetivo),
        String(antigo.dataLimite), null, 'eliminado', null,
        (req.jwtUser as any)?.nome || null
      );
    }
    json(res, 200, rows[0]);
  });

  // ── Emissões de Mini-Pauta (histórico) ──────────────────────────────────
