      if (anoLetivo) { params.push(anoLetivo); sql += ` AND "anoLetivo"=$${params.length}`; }
      if (trimestre) { params.push(Number(trimestre)); sql += ` AND trimestre=$${params.length}`; }
      if (emitidoPorId) { params.push(emitidoPorId); sql += ` AND "emitidoPorId"=$${params.length}`; }
      sql += ` ORDER BY "emitidoEm" DESC LIMIT 200`;
