  const ERRO_DIA_FECHADO = 'Este dia já tem um Fecho de Caixa activo. Solicite a reabertura do fecho para poder alterar estes pagamentos.';
  const ADMIN_ROLES = new Set(["ceo", "pca", "admin"]);

