  // ─── HELPER: extrair configuração EMIS normalizada de config_geral ──────────
  //     Usa colunas individuais (não a coluna dados que não existe).
  //     Suporta os dois nomes de campo (emisEntidadeId E numeroEntidade) para compatibilidade.
  async function getEmisConfig(): Promise<{
    entidadeId: string | undefined;
    apiKey: string | undefined;
    apiUrl: string | undefined;
    ambiente: string;
    habilitado: boolean;
    prazo: number;
    nomeBeneficiario: string | undefined;
  }> {
    const configRows = await query<JsonObject>(
      `SELECT "emisEntidadeId","numeroEntidade","emisApiKey","emisApiUrl","emisAmbiente",
              "emisHabilitado","emisPrazoPagamento","nomeBeneficiario"
       FROM public.config_geral ORDER BY id LIMIT 1`, []
    );
    const row: Record<string, unknown> = (configRows[0] as Record<string, unknown>) || {};
    // Suporta tanto emisEntidadeId (campo interno) como numeroEntidade (campo do formulário admin)
    // Valida que o entidadeId é numérico (1-9 dígitos) — formato obrigatório Multicaixa Angola
    const rawEntidade = (row.emisEntidadeId as string | undefined) || (row.numeroEntidade as string | undefined) || '';
    const entidadeId = /^\d{1,9}$/.test(rawEntidade.trim()) ? rawEntidade.trim() : undefined;
    const apiKey = row.emisApiKey as string | undefined;
    const apiUrl = row.emisApiUrl as string | undefined;
    const ambiente = (row.emisAmbiente as string) || 'sandbox';
    const habilitado = !!(row.emisHabilitado);
    const prazo = Number(row.emisPrazoPagamento) || 72; // 72h padrão para propinas escolares
    const nomeBeneficiario = row.nomeBeneficiario as string | undefined;
    return { entidadeId, apiKey, apiUrl, ambiente, habilitado, prazo, nomeBeneficiario };
  }

  // ─── HELPER: normalizar referência RUPE removendo espaços e formatação ───────────
  function normalizarReferencia(ref: string): string {
    return String(ref).replace(/\s+/g, '').trim();
  }

  // ─── HELPER: chamada à API EMIS — tenta vários formatos de resposta de bancos angolanos ─
  async function chamarEmisGerarReferencia(cfg: {
    apiUrl: string; apiKey: string; entidadeId: string;
    valor: number; descricao: string; dataValidade: Date;
    nif?: string; numeroBi?: string;
  }): Promise<string | null> {
    const base = cfg.apiUrl.endsWith('/') ? cfg.apiUrl : cfg.apiUrl + '/';
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 12000);
    try {
      const resp = await fetch(`${base}referencias`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${cfg.apiKey}`,
          'X-Entity-ID': cfg.entidadeId,
          'X-Entidade': cfg.entidadeId,
          'Api-Key': cfg.apiKey,
        },
        body: JSON.stringify({
          entidade: cfg.entidadeId,
          numero_entidade: cfg.entidadeId,
          valor: cfg.valor,
          montante: cfg.valor,
          descricao: cfg.descricao,
          description: cfg.descricao,
          validade: cfg.dataValidade.toISOString(),
          data_expiracao: cfg.dataValidade.toISOString(),
          expiry: cfg.dataValidade.toISOString(),
          // Identificação do pagador — exigido por alguns bancos angolanos (BFA, BAI, BIC...)
          ...(cfg.nif ? { nif: cfg.nif, nif_pagador: cfg.nif } : {}),
          ...(cfg.numeroBi ? { numero_bi: cfg.numeroBi, bi_pagador: cfg.numeroBi, document_number: cfg.numeroBi } : {}),
        }),
        signal: controller.signal,
      });
      clearTimeout(timeoutId);
      if (!resp.ok) {
        const errText = await resp.text().catch(() => '');
        console.warn(`[EMIS gerar-referencia] Erro HTTP ${resp.status}:`, errText.slice(0, 200));
        return null;
      }
      const data = await resp.json() as Record<string, unknown>;
      // Aceita múltiplos formatos de resposta
      const ref = (
        (data.referencia as string) ||
        (data.codigoReferencia as string) ||
        (data.codigo_referencia as string) ||
        (data.reference as string) ||
        (data.ref as string) ||
        (data.numero_referencia as string) ||
        (data.transactionRef as string) ||
        ((data.data as Record<string, unknown>)?.referencia as string)
      );
      return ref || null;
    } catch (err: unknown) {
      clearTimeout(timeoutId);
      console.warn('[EMIS gerar-referencia] Falha na chamada:', (err as Error).message);
      return null;
    }
  }

  // ─── HELPER: verificar estado de pagamento junto da API EMIS ───────────────────
  async function chamarEmisVerificarEstado(cfg: {
    apiUrl: string; apiKey: string; entidadeId: string; referencia: string;
  }): Promise<{ pago: boolean; estado?: string; dataPagamento?: string; valor?: number } | null> {
    const base = cfg.apiUrl.endsWith('/') ? cfg.apiUrl : cfg.apiUrl + '/';
    const refNorm = normalizarReferencia(cfg.referencia);
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 10000);
    try {
      const resp = await fetch(`${base}referencias/${encodeURIComponent(refNorm)}`, {
        method: 'GET',
        headers: {
          'Authorization': `Bearer ${cfg.apiKey}`,
          'X-Entity-ID': cfg.entidadeId,
          'X-Entidade': cfg.entidadeId,
          'Api-Key': cfg.apiKey,
        },
        signal: controller.signal,
      });
      clearTimeout(timeoutId);
      if (!resp.ok) {
        console.warn(`[EMIS verificar] Erro HTTP ${resp.status} para ref=${cfg.referencia}`);
        return null;
      }
      const data = await resp.json() as Record<string, unknown>;
      const pago = !!(
        data.pago === true ||
        String(data.status || '').toLowerCase() === 'pago' ||
        String(data.estado || '').toLowerCase() === 'pago' ||
        String(data.state || '').toLowerCase() === 'paid' ||
        String(data.paymentStatus || '').toLowerCase() === 'paid'
      );
      return {
        pago,
        estado: (data.estado as string) || (data.status as string) || (data.state as string),
        dataPagamento: (data.dataPagamento as string) || (data.paymentDate as string) || (data.paidAt as string),
        valor: Number(data.valor || data.amount || data.montante || 0) || undefined,
      };
    } catch (err: unknown) {
      clearTimeout(timeoutId);
      console.warn('[EMIS verificar] Falha na chamada:', (err as Error).message);
      return null;
    }
  }

  // ─── HELPER CENTRAL: marcar um RUPE como pago e GARANTIR o reflexo em pagamentos.
  //      Usado pelo webhook EMIS, pelas rotas de verificação manual e pelo PUT manual.
  //      Idempotente: pode ser chamado várias vezes para o mesmo RUPE sem duplicar. ──
  async function confirmarRupeComoPago(
    rupeId: string,
    opts?: {
      valorPago?: number;
      dataPagamento?: string;
      metodoPagamento?: string;
      origem?: string;
      observacao?: string;
    }
  ): Promise<{ rupe: JsonObject; pagamento: JsonObject | null; jaEstavaPago: boolean }> {
    const [rupe] = await query<JsonObject>(`SELECT * FROM public.rupes WHERE id=$1`, [rupeId]);
    if (!rupe) throw new Error('RUPE não encontrado.');

    const jaEstavaPago = rupe.status === 'pago';
    const referencia = String(rupe.referencia || '');
    const alunoIdRaw = String(rupe.alunoId || '').trim();
    const alunoId = alunoIdRaw.length > 0 ? alunoIdRaw : null;
    const taxaId = (rupe.taxaId as string) || null;
    const categoria = String((rupe as any).categoria || 'propina');
    const mesRupe = (rupe as any).mes != null ? Number((rupe as any).mes) : null;
    const anoRupe = (rupe as any).ano != null && String((rupe as any).ano).trim() !== '' ? String((rupe as any).ano) : null;
    const valorPago = Number(opts?.valorPago ?? rupe.valor ?? 0);
    const dataPagamento = opts?.dataPagamento || new Date().toISOString();
    const metodoPagamento = opts?.metodoPagamento || 'referencia_bancaria';
    const origem = opts?.origem || 'webhook_emis';
    const obsExtra = opts?.observacao || `Confirmação automática (${origem}) em ${new Date().toISOString()}`;

    if (!jaEstavaPago) {
      await query(`UPDATE public.rupes SET status='pago' WHERE id=$1`, [rupeId]);
    }

    // Categoria especial: recarga de saldo do aluno → credita saldo, não cria pagamento
    if (categoria === 'deposito_saldo' && alunoId) {
      let pagamento: JsonObject | null = null;
      if (!jaEstavaPago) {
        const client = await pool.connect();
        try {
          await client.query('BEGIN');
          const sRes = await client.query(`SELECT * FROM public.saldo_alunos WHERE "alunoId"=$1`, [alunoId]);
          if (sRes.rows[0]) {
            const novo = parseFloat(sRes.rows[0].saldo) + valorPago;
            await client.query(`UPDATE public.saldo_alunos SET saldo=$1, "updatedAt"=NOW() WHERE "alunoId"=$2`, [novo, alunoId]);
          } else {
            await client.query(`INSERT INTO public.saldo_alunos ("alunoId", saldo) VALUES ($1, $2)`, [alunoId, valorPago]);
          }
          await client.query(
            `INSERT INTO public.movimentos_saldo ("alunoId", tipo, valor, descricao, "criadoPor")
             VALUES ($1,'credito',$2,$3,$4)`,
            [alunoId, valorPago, `Recarga via RUPE ${referencia}`, origem]
          );
          await client.query('COMMIT');
        } catch (e) {
          await client.query('ROLLBACK');
          throw e;
        } finally {
          client.release();
        }
      }
      const [rupeFinal] = await query<JsonObject>(`SELECT * FROM public.rupes WHERE id=$1`, [rupeId]);
      return { rupe: rupeFinal || rupe, pagamento, jaEstavaPago };
    }

    // Tentar reaproveitar pagamento pendente com a mesma referência (criado pelo aluno)
    let pagamento: JsonObject | null = null;
    const existentes = await query<JsonObject>(
      `SELECT id FROM public.pagamentos WHERE referencia=$1 AND status<>'pago' LIMIT 1`,
      [referencia]
    );
    if (existentes && existentes.length > 0) {
      const updRows = await query<JsonObject>(
        `UPDATE public.pagamentos
            SET status='pago', data=$1, "metodoPagamento"=$2,
                observacao = COALESCE(observacao,'') || ' | ' || $3
          WHERE id=$4 RETURNING *`,
        [dataPagamento, metodoPagamento, obsExtra, (existentes[0] as any).id]
      );
      pagamento = updRows[0] || null;
    } else {
      // Verificar se já existe um pagamento PAGO para esta referência (idempotência)
      const jaPagos = await query<JsonObject>(
        `SELECT * FROM public.pagamentos WHERE referencia=$1 AND status='pago' LIMIT 1`,
        [referencia]
      );
      if (jaPagos && jaPagos.length > 0) {
        pagamento = jaPagos[0];
      } else {
        // Se o RUPE tiver mes/ano associados (gerado a partir da caderneta de propinas),
        // usa-os para que o mês fique automaticamente marcado como pago; caso contrário,
        // recorre ao ano lectivo activo (comportamento anterior, RUPEs sem mês definido).
        const anoAtual = anoRupe || await getAnoLetivoAtivo();
        const insRows = await query<JsonObject>(
          `INSERT INTO public.pagamentos
            (id, "alunoId", "taxaId", valor, data, mes, ano, status, "metodoPagamento", referencia, observacao)
           VALUES (gen_random_uuid(), $1, $2, $3, $4, $5, $6, 'pago', $7, $8, $9) RETURNING *`,
          [alunoId, taxaId, valorPago, dataPagamento, mesRupe, normalizeAnoPagamento(anoAtual), metodoPagamento, referencia, obsExtra]
        );
        pagamento = insRows[0] || null;
      }
    }

    const [rupeFinal] = await query<JsonObject>(`SELECT * FROM public.rupes WHERE id=$1`, [rupeId]);
    return { rupe: rupeFinal || rupe, pagamento, jaEstavaPago };
  }

