  // ── Recarga de saldo via RUPE: gera referência EMIS especial que, quando paga,
  //    credita directamente o saldo do aluno (sem criar pagamento de propina). ──
  async function gerarRupeRecargaSaldo(alunoId: string, valor: number): Promise<JsonObject> {
    if (!Number.isFinite(valor) || valor <= 0) throw new Error('Valor inválido.');
    const emisCfg = await getEmisConfig();
    const dataGeracao = new Date();
    const dataValidade = new Date(dataGeracao.getTime() + emisCfg.prazo * 60 * 60 * 1000);
    // Buscar NIF/BI do aluno
    const [alunoDocRec] = await query<{ nif: string; numeroBi: string; numeroCedula: string }>(
      `SELECT nif, "numeroBi", "numeroCedula" FROM public.alunos WHERE id=$1 LIMIT 1`,
      [alunoId]
    ).catch(() => [null as any]);
    const nifRec = alunoDocRec?.nif || alunoDocRec?.numeroCedula || '';
    const biRec = alunoDocRec?.numeroBi || '';
    const entRec = (emisCfg.entidadeId || '99999').padStart(5, '0');
    let referencia: string;
    if (emisCfg.ambiente === 'producao' && emisCfg.entidadeId && emisCfg.apiKey && emisCfg.apiUrl) {
      const ref = await chamarEmisGerarReferencia({
        apiUrl: emisCfg.apiUrl, apiKey: emisCfg.apiKey, entidadeId: emisCfg.entidadeId,
        valor, descricao: 'Recarga de Saldo', dataValidade,
        nif: nifRec || undefined, numeroBi: biRec || undefined,
      });
      referencia = ref || `${entRec} ${String((Date.now() + 1) % 999999999).padStart(9, '0')}`;
    } else {
      referencia = `${entRec} ${String(Date.now() % 999999999).padStart(9, '0')}`;
    }
    const rows = await query<JsonObject>(
      `INSERT INTO public.rupes (id,"alunoId","taxaId","valor","referencia","dataGeracao","dataValidade","status",categoria)
       VALUES (gen_random_uuid(), $1, NULL, $2, $3, $4, $5, 'ativo', 'deposito_saldo') RETURNING *`,
      [alunoId, valor, referencia, dataGeracao.toISOString(), dataValidade.toISOString()]
    );
    return rows[0];
  }

