      const [userRow] = await query<JsonObject>(
        `SELECT u."alunoId", a.id as "alunoIdFallback"
         FROM public.utilizadores u LEFT JOIN public.alunos a ON a."utilizadorId"=u.id WHERE u.id=$1`,
        [req.jwtUser.userId]
      );
      const resolvedAlunoId = userRow?.alunoId || userRow?.alunoIdFallback;
      if (!resolvedAlunoId) return json(res, 403, { error: "Utilizador não está associado a nenhum aluno." });
      const valor = Number((requireBodyObject(req) as any).valor);
      const rupe = await gerarRupeRecargaSaldo(String(resolvedAlunoId), valor);
      json(res, 201, rupe);
