  // Upload de ficheiros/imagens para o chat
  const chatUploadDir = path.join(process.cwd(), 'uploads', 'chat');
  fs.mkdirSync(chatUploadDir, { recursive: true });

  const chatUpload = multer({
    storage: multer.diskStorage({
      destination: (_req, _file, cb) => cb(null, chatUploadDir),
      filename: (_req, file, cb) => {
        const ext = path.extname(file.originalname).toLowerCase();
        cb(null, `${Date.now()}-${crypto.randomBytes(6).toString('hex')}${ext}`);
      },
    }),
    limits: { fileSize: 15 * 1024 * 1024 },
    fileFilter: (_req, file, cb) => {
      const ok = /^(image\/(jpeg|png|gif|webp)|application\/(pdf|msword|vnd\.openxmlformats-officedocument\.(wordprocessingml\.document|spreadsheetml\.sheet))|text\/plain)$/.test(file.mimetype);
      cb(null, ok);
    },
  });

  app.post('/api/chat-interno/upload', requireAuth, (req: Request, res: Response, next: any) => {
    chatUpload.single('file')(req, res, (err: any) => {
      if (err) return json(res, 400, { error: err.message || 'Erro ao fazer upload.' });
      if (!req.file) return json(res, 400, { error: 'Nenhum ficheiro enviado.' });
      const isImage = req.file.mimetype.startsWith('image/');
      json(res, 200, {
        url: `/api/chat-interno/files/${req.file.filename}`,
        nome: req.file.originalname,
        tipo: isImage ? 'image' : 'file',
        tamanho: req.file.size,
      });
    });
  });

