  app.get("/api/config", async (_req: Request, res: Response) => {
    const rows = await query<JsonObject>(`SELECT * FROM public.config_geral ORDER BY id ASC LIMIT 1`, []);
    let config = rows[0];
    if (!config) {
      const created = await query<JsonObject>(
        `INSERT INTO public.config_geral DEFAULT VALUES RETURNING *`, [],
      );
      config = created[0];
    }
    // Auto-inicializar datas de licença apenas quando NENHUMA data existe (instalação nova)
    // NUNCA sobrescreve se já houver licencaExpiracao definida — previne reset acidental ao migrar BD
    if (!config.licencaAtivacao && !config.licencaExpiracao) {
      // Usar CURRENT_DATE do PostgreSQL para evitar desvios de fuso horário UTC/local
      const updated = await query<JsonObject>(
        `UPDATE public.config_geral
         SET "licencaAtivacao" = CURRENT_DATE::text,
             "licencaExpiracao" = (CURRENT_DATE + INTERVAL '30 days')::text,
             "licencaPlano" = $1
         WHERE id = $2 RETURNING *`,
        ['avaliacao', config.id],
      );
      config = updated[0];
    }
    // Mascarar chaves de API sensíveis — apenas indica se estão configuradas
    const safeConfig = { ...config };
    if (safeConfig.groqApiKey) safeConfig.groqApiKey = 'configured';
    if (safeConfig.openaiApiKey) safeConfig.openaiApiKey = 'configured';
    // Incluir nomes das disciplinas nucleares Art. 23 (tabela separada)
    try {
      const nucRows = await query<{ nome: string }>(`SELECT nome FROM public.disciplinas WHERE "nuclearArt23" = true ORDER BY nome`, []);
      (safeConfig as any).disciplinasNuclearArt23 = nucRows.map(r => r.nome);
    } catch { (safeConfig as any).disciplinasNuclearArt23 = []; }
    json(res, 200, safeConfig);
  });

