  // GET /api/licenca/alunos-matriculados — conta alunos com situação 'activo' para cálculo de preço
  // Usa high-water mark para evitar fraude por desactivação de alunos antes da facturação
  app.get("/api/licenca/alunos-matriculados", async (_req: Request, res: Response) => {
    try {
      // Conta apenas alunos genuinamente activos (ativo=true E situacao='activo')
      const rows = await query<{ total: string }>(
        `SELECT COUNT(*) AS total FROM public.alunos
         WHERE ativo = true AND (situacao IS NULL OR situacao = 'activo')`,
        []
      );
      const total = parseInt(rows[0]?.total || '0', 10);

      // High-water mark: o máximo histórico desde o último reset de facturação
      const cfg = await query<any>(
        `SELECT "alunosHighWaterMark","alunosHighWaterMarkAt","alunosHighWaterMarkResetAt" FROM public.config_geral LIMIT 1`, []
      );
      const hwm = Number(cfg[0]?.alunosHighWaterMark || 0);
      const agora = new Date().toISOString();

      // Se o total actual superar o high-water mark, actualiza automaticamente
      if (total > hwm) {
        await query(
          `UPDATE public.config_geral SET "alunosHighWaterMark"=$1, "alunosHighWaterMarkAt"=$2`,
          [total, agora]
        );
        json(res, 200, { total, highWaterMark: total, highWaterMarkAt: agora, highWaterMarkResetAt: cfg[0]?.alunosHighWaterMarkResetAt || '' });
      } else {
        json(res, 200, { total, highWaterMark: hwm, highWaterMarkAt: cfg[0]?.alunosHighWaterMarkAt || '', highWaterMarkResetAt: cfg[0]?.alunosHighWaterMarkResetAt || '' });
      }
    } catch (e) {
      json(res, 500, { error: (e as Error).message });
    }
  });

  // POST /api/licenca/watermark/reset — CEO reinicia o high-water mark (início de novo período)
  app.post("/api/licenca/watermark/reset", requireAuth, async (req: Request, res: Response) => {
    if (req.jwtUser?.role !== 'ceo') return json(res, 403, { error: 'Acesso restrito ao CEO.' });
    try {
      const rows = await query<{ total: string }>(
        `SELECT COUNT(*) AS total FROM public.alunos WHERE ativo=true AND (situacao IS NULL OR situacao='activo')`, []
      );
      const total = parseInt(rows[0]?.total || '0', 10);
      const agora = new Date().toISOString();
      await query(
        `UPDATE public.config_geral SET "alunosHighWaterMark"=$1,"alunosHighWaterMarkAt"=$2,"alunosHighWaterMarkResetAt"=$3`,
        [total, agora, agora]
      );
      json(res, 200, { success: true, highWaterMark: total, resetAt: agora });
    } catch (e) { json(res, 500, { error: (e as Error).message }); }
  });

