  app.put('/api/modelos-avaliacao/:id', requireAuth, async (req: Request, res: Response) => {
    const role = req.jwtUser?.role;
    if (!['ceo','admin','director'].includes(role ?? '')) return json(res, 403, { error: 'Acesso negado' });
    try {
      const { id } = req.params;
      const b = requireBodyObject(req);
      const rows = await query<JsonObject>(
        `UPDATE public.modelos_avaliacao SET
          nome=$2,nivel_ensino=$3,descricao=$4,cor=$5,icone=$6,
          perc_mac=$7,perc_pp=$8,perc_nt=$9,perc_pt=$10,perc_pg=$11,perc_exame=$12,
          mac_min=$13,mac_max=$14,tipo_escala=$15,tem_npp=$16,tem_npt=$17,atualizado_em=NOW()
         WHERE id=$1 RETURNING *`,
        [id,b.nome,b.nivelEnsino,b.descricao,b.cor,b.icone,
         b.percMac,b.percPp,b.percNt,b.percPt,b.percPg,b.percExame,
         b.macMin,b.macMax,b.tipoEscala,b.temNPP!==false,b.temNPT!==false]
      );
      if (!rows.length) return json(res, 404, { error: 'Modelo não encontrado' });
      // Se for o modelo activo, propaga os novos valores para config_geral também
      const cfg = await query<{modeloAvaliacao:string|null}>(`SELECT "modeloAvaliacao" FROM public.config_geral LIMIT 1`, []);
      if (cfg[0]?.modeloAvaliacao === id) {
        await query(
          `UPDATE public.config_geral SET "percMac"=$1,"percPp"=$2,"percNt"=$3,"percPt"=$4,"percPg"=$5,"percExame"=$6,
            "macMin"=$7,"macMax"=$8,"tipoEscala"=$9,"temNPP"=$10,"temNPT"=$11,"pp1Habilitado"=$10,"pptHabilitado"=$11 WHERE TRUE`,
          [b.percMac,b.percPp,b.percNt,b.percPt,b.percPg,b.percExame,b.macMin,b.macMax,b.tipoEscala,b.temNPP!==false,b.temNPT!==false]
        );
        invalidateSchoolNameCache();
        void refreshSchoolNameCache();
      }
      json(res, 200, rows[0]);
    } catch (e) { json(res, 500, { error: (e as Error).message }); }
  });

  app.delete('/api/modelos-avaliacao/:id', requireAuth, async (req: Request, res: Response) => {
    const role = req.jwtUser?.role;
    if (!['ceo','admin'].includes(role ?? '')) return json(res, 403, { error: 'Acesso negado' });
    try {
      const { id } = req.params;
      const check = await query<{predefinido:boolean}>(`SELECT predefinido FROM public.modelos_avaliacao WHERE id=$1`, [id]);
      if (!check.length) return json(res, 404, { error: 'Modelo não encontrado' });
      if (check[0].predefinido) return json(res, 400, { error: 'Modelos predefinidos não podem ser eliminados' });
      await query(`DELETE FROM public.modelos_avaliacao WHERE id=$1`, [id]);
      json(res, 200, { success: true });
    } catch (e) { json(res, 500, { error: (e as Error).message }); }
  });

  // POST /api/modelos-avaliacao/:id/ativar
  // Activa um modelo: propaga todos os seus campos para config_geral e marca-o como activo na BD.
  app.post('/api/modelos-avaliacao/:id/ativar', requireAuth, async (req: Request, res: Response) => {
    const role = req.jwtUser?.role;
    if (!['ceo','admin','director'].includes(role ?? '')) return json(res, 403, { error: 'Acesso negado' });
    try {
      const { id } = req.params;
      const rows = await query<JsonObject>(`SELECT * FROM public.modelos_avaliacao WHERE id=$1`, [id]);
      if (!rows.length) return json(res, 404, { error: 'Modelo não encontrado' });
      const m = rows[0] as any;
      // Propaga todos os campos do modelo para config_geral
      await query(
        `UPDATE public.config_geral SET
          "percMac"=$1,"percPp"=$2,"percNt"=$3,"percPt"=$4,"percPg"=$5,"percExame"=$6,
          "macMin"=$7,"macMax"=$8,"tipoEscala"=$9,"temNPP"=$10,"temNPT"=$11,
          "pp1Habilitado"=$10,"pptHabilitado"=$11,"modeloAvaliacao"=$12
         WHERE TRUE`,
        [m.perc_mac,m.perc_pp,m.perc_nt,m.perc_pt,m.perc_pg,m.perc_exame,
         m.mac_min,m.mac_max,m.tipo_escala,m.tem_npp,m.tem_npt,id]
      );
      // Marca este como activo, desactiva os restantes
      await query(`UPDATE public.modelos_avaliacao SET ativo=(id=$1),atualizado_em=NOW() WHERE TRUE`, [id]);
      invalidateSchoolNameCache();
      void refreshSchoolNameCache();
      json(res, 200, {
        success: true, id,
        percMac:m.perc_mac, percPp:m.perc_pp, percNt:m.perc_nt, percPt:m.perc_pt,
        percPg:m.perc_pg, percExame:m.perc_exame,
        macMin:m.mac_min, macMax:m.mac_max, tipoEscala:m.tipo_escala,
        temNPP:m.tem_npp, temNPT:m.tem_npt,
      });
    } catch (e) { json(res, 500, { error: (e as Error).message }); }
  });

