  async function seedDocTemplates() {
    try {
      await query(`CREATE TABLE IF NOT EXISTS public.doc_deleted_seeds (seed_id TEXT PRIMARY KEY)`, []);
      const deletedRows = await query<{ seed_id: string }>(`SELECT seed_id FROM public.doc_deleted_seeds`, []);
      const deletedSeedIds = new Set(deletedRows.map((row) => row.seed_id));
      for (const seed of DOC_SEEDS) {
        if (deletedSeedIds.has(seed.id)) continue;
        await query(
          `INSERT INTO public.doc_templates (id, nome, tipo, conteudo, classe_alvo, bloqueado)
           VALUES ($1,$2,$3,$4,$5,$6)
           ON CONFLICT (id) DO UPDATE SET
             nome=EXCLUDED.nome,
             tipo=EXCLUDED.tipo,
             classe_alvo=EXCLUDED.classe_alvo,
             atualizado_em=NOW()
           WHERE doc_templates.bloqueado=false`,
          [seed.id, seed.nome, seed.tipo, seed.conteudo, seed.classeAlvo ?? null, seed.bloqueado ?? false]
        );
      }
      console.log(`[seed] doc_templates: ${DOC_SEEDS.length} modelos predefinidos verificados/inseridos.`);
    } catch (e) {
      console.error('[seed] Erro ao popular doc_templates:', e);
    }
  }
