  // GET /api/lookup/:categoria — público (sem auth)
  app.get("/api/lookup/:categoria", async (req: Request, res: Response) => {
    try {
      const { categoria } = req.params;
      let rows = await query<JsonObject>(
        `SELECT id, categoria, valor, label, ordem, ativo, icon, cor FROM public.lookup_items WHERE categoria=$1 AND ativo=true ORDER BY ordem ASC, label ASC`,
        [categoria]
      );
      // Se a escola não tem 13ª Classe, remover da lista de classes
      if (categoria === 'classes') {
        const cfgRows = await query<JsonObject>(`SELECT "temDecimaTermeira" FROM public.config_geral LIMIT 1`, []);
        const tem13: boolean = (cfgRows[0] as any)?.temDecimaTermeira !== false;
        if (!tem13) {
          rows = (rows as any[]).filter((r: any) => r.valor !== '13ª Classe') as any;
        }
      }
      json(res, 200, rows);
    } catch (e) { json(res, 500, { error: (e as Error).message }); }
  });

  // GET /api/lookup — lista todas as categorias disponíveis (admin)
  app.get("/api/lookup", requireAuth, async (_req: Request, res: Response) => {
    try {
      const rows = await query<JsonObject>(
        `SELECT DISTINCT categoria FROM public.lookup_items ORDER BY categoria ASC`, []
      );
      json(res, 200, rows.map((r: any) => r.categoria));
    } catch (e) { json(res, 500, { error: (e as Error).message }); }
  });

  // POST /api/lookup — criar item (admin)
  app.post("/api/lookup", requireAuth, requirePermission(["admin", "configuracoes_sistema", "financeiro"]), async (req: Request, res: Response) => {
    try {
      const { categoria, valor, label, ordem, icon, cor } = requireBodyObject(req) as any;
      if (!categoria || !valor || !label) return json(res, 400, { error: 'categoria, valor e label são obrigatórios.' });
      // Utilizadores financeiro só podem criar tipos relacionados com finanças.
      const role = req.jwtUser?.role;
      if (role && role !== 'admin' && role !== 'ceo' && role !== 'pca') {
        const perms = await getUserPermissions(req.jwtUser!.userId, role);
        const isAdminLike = perms.includes('admin') || perms.includes('configuracoes_sistema') || perms.includes('*');
        if (!isAdminLike) {
          const allowedCategorias = ['tipos_taxa', 'metodos_pagamento'];
          if (!allowedCategorias.includes(String(categoria))) {
            return json(res, 403, { error: `Sem permissão para criar itens na categoria '${categoria}'.` });
          }
        }
      }
      const rows = await query<JsonObject>(
        `INSERT INTO public.lookup_items (categoria, valor, label, ordem, ativo, icon, cor) VALUES ($1,$2,$3,$4,true,$5,$6) RETURNING *`,
        [categoria, valor, label, ordem ?? 99, icon ?? null, cor ?? null]
      );
      json(res, 201, rows[0]);
    } catch (e) { json(res, 400, { error: (e as Error).message }); }
  });

  // PUT /api/lookup/:id — atualizar item (admin, ou financeiro para label/icon/cor em tipos_taxa/metodos_pagamento)
  app.put("/api/lookup/:id", requireAuth, requirePermission(["admin", "configuracoes_sistema", "financeiro"]), async (req: Request, res: Response) => {
    try {
      const { id } = req.params;
      const { valor, label, ordem, ativo, icon, cor } = requireBodyObject(req) as any;

      // Carrega o item para validar permissões e proteger seeds.
      const existing = await query<{ categoria: string; valor: string }>(
        `SELECT categoria, valor FROM public.lookup_items WHERE id=$1`, [id]
      );
      if (!existing[0]) return json(res, 404, { error: 'Item não encontrado.' });
      const item = existing[0];

      // Determina se quem chama é admin-like.
      const role = req.jwtUser?.role;
      let isAdminLike = role === 'admin' || role === 'ceo' || role === 'pca';
      if (!isAdminLike && role) {
        const perms = await getUserPermissions(req.jwtUser!.userId, role);
        isAdminLike = perms.includes('admin') || perms.includes('configuracoes_sistema') || perms.includes('*');
      }

      if (!isAdminLike) {
        const allowedCategorias = ['tipos_taxa', 'metodos_pagamento'];
        if (!allowedCategorias.includes(String(item.categoria))) {
          return json(res, 403, { error: `Sem permissão para editar itens na categoria '${item.categoria}'.` });
        }
        // Não-admin não pode mudar o slug (valor) — partiria as referências em taxas/pagamentos.
        if (valor !== undefined && valor !== item.valor) {
          return json(res, 403, { error: 'Apenas administradores podem alterar o identificador interno do tipo. Pode editar o nome, ícone e cor.' });
        }
      }

      // Bloqueia alteração do slug em seeds predefinidos do sistema (mesmo para admin).
      const SEED_DEFAULTS: Record<string, string[]> = {
        tipos_taxa: ['propina', 'matricula', 'material', 'exame', 'multa', 'outro'],
        metodos_pagamento: ['dinheiro', 'transferencia', 'multicaixa'],
      };
      const seedsForCat = SEED_DEFAULTS[item.categoria];
      if (seedsForCat && seedsForCat.includes(item.valor) && valor !== undefined && valor !== item.valor) {
        return json(res, 400, { error: 'O identificador de um tipo predefinido não pode ser alterado.' });
      }

      const setParts: string[] = []; const values: unknown[] = [];
      if (valor !== undefined) { values.push(valor); setParts.push(`valor=$${values.length}`); }
      if (label !== undefined) { values.push(label); setParts.push(`label=$${values.length}`); }
      if (ordem !== undefined) { values.push(ordem); setParts.push(`ordem=$${values.length}`); }
      if (ativo !== undefined) { values.push(ativo); setParts.push(`ativo=$${values.length}`); }
      if (icon  !== undefined) { values.push(icon);  setParts.push(`icon=$${values.length}`); }
      if (cor   !== undefined) { values.push(cor);   setParts.push(`cor=$${values.length}`); }
      if (!setParts.length) return json(res, 400, { error: 'Nenhum campo para atualizar.' });
      values.push(id);
      const rows = await query<JsonObject>(
        `UPDATE public.lookup_items SET ${setParts.join(',')} WHERE id=$${values.length} RETURNING *`, values
      );
      json(res, 200, rows[0]);
    } catch (e) { json(res, 400, { error: (e as Error).message }); }
  });

  // DELETE /api/lookup/:id — remover item (admin, ou financeiro para tipos_taxa/metodos_pagamento)
  app.delete("/api/lookup/:id", requireAuth, requirePermission(["admin", "configuracoes_sistema", "financeiro"]), async (req: Request, res: Response) => {
    try {
      const { id } = req.params;
      // Carrega o item antes de apagar para validar permissões e impedir remoção de seeds.
      const existing = await query<{ id: string; categoria: string; valor: string }>(
        `SELECT id::text AS id, categoria, valor FROM public.lookup_items WHERE id=$1`, [id]
      );
      if (!existing[0]) return json(res, 404, { error: 'Tipo não encontrado.' });
      const item = existing[0];

      // Restringe categorias permitidas a quem não é admin
      const role = req.jwtUser?.role;
      if (role && role !== 'admin' && role !== 'ceo' && role !== 'pca') {
        const perms = await getUserPermissions(req.jwtUser!.userId, role);
        const isAdminLike = perms.includes('admin') || perms.includes('configuracoes_sistema') || perms.includes('*');
        if (!isAdminLike) {
          const allowedCategorias = ['tipos_taxa', 'metodos_pagamento'];
          if (!allowedCategorias.includes(String(item.categoria))) {
            return json(res, 403, { error: `Sem permissão para apagar itens na categoria '${item.categoria}'.` });
          }
        }
      }

      // Protege os valores predefinidos do sistema.
      const SEED_DEFAULTS: Record<string, string[]> = {
        tipos_taxa: ['propina', 'matricula', 'material', 'exame', 'multa', 'outro'],
        metodos_pagamento: ['dinheiro', 'transferencia', 'multicaixa'],
      };
      const seedsForCat = SEED_DEFAULTS[item.categoria];
      if (seedsForCat && seedsForCat.includes(item.valor)) {
        return json(res, 400, { error: 'Não é possível apagar um tipo predefinido do sistema.' });
      }

      // Impede a remoção se houver registos a usar este valor (apenas para tipos_taxa/metodos_pagamento).
      if (item.categoria === 'tipos_taxa') {
        const usedTaxas = await query<{ c: string }>(`SELECT COUNT(*)::text AS c FROM public.taxas WHERE tipo=$1`, [item.valor]);
        const usedPag = await query<{ c: string }>(`SELECT COUNT(*)::text AS c FROM public.pagamentos p JOIN public.taxas t ON t.id = p."taxaId" WHERE t.tipo=$1`, [item.valor]);
        const total = parseInt(usedTaxas[0]?.c ?? '0') + parseInt(usedPag[0]?.c ?? '0');
        if (total > 0) {
          return json(res, 409, { error: `Este tipo está a ser usado por ${parseInt(usedTaxas[0]?.c ?? '0')} rubrica(s). Apague ou altere as rubricas antes de remover o tipo.` });
        }
      }
      if (item.categoria === 'metodos_pagamento') {
        const usedPag = await query<{ c: string }>(`SELECT COUNT(*)::text AS c FROM public.pagamentos WHERE "metodoPagamento"=$1`, [item.valor]);
        if (parseInt(usedPag[0]?.c ?? '0') > 0) {
          return json(res, 409, { error: `Este método já foi usado em ${usedPag[0].c} pagamento(s) e não pode ser removido.` });
        }
      }

      const rows = await query<{ categoria: string; valor: string }>(`DELETE FROM public.lookup_items WHERE id=$1 RETURNING categoria, valor`, [id]);
      if (rows[0]) {
        await query(`CREATE TABLE IF NOT EXISTS public.lookup_deleted_seeds (categoria TEXT NOT NULL, valor TEXT NOT NULL, PRIMARY KEY (categoria, valor))`, []);
        await query(`INSERT INTO public.lookup_deleted_seeds (categoria, valor) VALUES ($1, $2) ON CONFLICT DO NOTHING`, [rows[0].categoria, rows[0].valor]);
      }
      json(res, 200, { ok: true });
    } catch (e) { json(res, 500, { error: (e as Error).message }); }
  });

  // -----------------------
  // DOCUMENTOS EMITIDOS (HISTÓRICO)
  // -----------------------
  app.get("/api/documentos-emitidos", requireAuth, requirePermission("arquivo_documentos"), async (req: Request, res: Response) => {
    try {
      const { alunoId, tipo, anoAcademico, search } = req.query as Record<string, string>;
      const conditions: string[] = [];
      const values: unknown[] = [];
      if (alunoId) { conditions.push(`aluno_id=$${values.length+1}`); values.push(alunoId); }
      if (tipo) { conditions.push(`tipo=$${values.length+1}`); values.push(tipo); }
      if (anoAcademico) { conditions.push(`ano_academico=$${values.length+1}`); values.push(anoAcademico); }
      if (search) {
        conditions.push(`(aluno_nome ILIKE $${values.length+1} OR aluno_num ILIKE $${values.length+1} OR tipo ILIKE $${values.length+1})`);
        values.push(`%${search}%`);
      }
      const where = conditions.length ? `WHERE ${conditions.join(' AND ')}` : '';
      const rows = await query<JsonObject>(
        `SELECT id, aluno_id AS "alunoId", aluno_nome AS "alunoNome", aluno_num AS "alunoNum",
                aluno_turma AS "alunoTurma", tipo, finalidade, ano_academico AS "anoAcademico",
                emitido_por AS "emitidoPor", emitido_em AS "emitidoEm", dados_snapshot AS "dadosSnapshot"
         FROM public.documentos_emitidos ${where} ORDER BY emitido_em DESC`,
        values
      );
      json(res, 200, rows);
    } catch (e) { json(res, 500, { error: (e as Error).message }); }
  });

