  // Esvaziar lixo — elimina permanentemente todos os modelos no lixo
  // NOTA: deve vir ANTES de /:id para não ser capturado como id='esvaziar-lixo'
  app.delete("/api/doc-templates/esvaziar-lixo", requireAuth, async (_req: Request, res: Response) => {
    try {
      const rows = await query<{ id: string }>(`SELECT id FROM public.doc_templates WHERE eliminado_em IS NOT NULL`, []);
      const ids = rows.map(r => r.id);
      if (ids.length > 0) {
        await query(`DELETE FROM public.doc_templates WHERE eliminado_em IS NOT NULL`, []);
        await query(`CREATE TABLE IF NOT EXISTS public.doc_deleted_seeds (seed_id TEXT PRIMARY KEY)`, []);
        for (const id of ids) {
          await query(`INSERT INTO public.doc_deleted_seeds (seed_id) VALUES ($1) ON CONFLICT DO NOTHING`, [id]);
        }
      }
      json(res, 200, { ok: true, count: ids.length });
    } catch (e) { json(res, 500, { error: (e as Error).message }); }
  });

