  // /minha MUST come before /:professorId to avoid Express treating 'minha' as an id
  app.get('/api/mini-pauta-atribuicoes/minha', requireAuth, async (req: Request, res: Response) => {
    try {
      const user = req.jwtUser as any;
      const profs = await query<{ id: string }>(
        `SELECT id FROM public.professores WHERE "utilizadorId"=$1`,
        [user.id]
      );
      if (!profs.length) return json(res, 404, { error: 'Professor não encontrado.' });
      const professorId = profs[0].id;
      const rows = await query<JsonObject>(
        `SELECT a.*, t.conteudo, t.nome AS "templateNome"
         FROM public.mini_pauta_atribuicoes a
         JOIN public.doc_templates t ON t.id = a."templateId"
         WHERE a."professorId" = $1
         ORDER BY a."disciplinaNome" ASC`,
        [professorId]
      );
      if (!rows.length) return json(res, 404, { error: 'Sem modelo atribuído.' });
      json(res, 200, rows);
    } catch (e) { json(res, 500, { error: (e as Error).message }); }
  });

