  /**
   * GET /api/disciplinas/alunos-prova
   * Lista alunos com média negativa na disciplina em que o seu ano actual coincide
   * com a classeFim da disciplina (terminal ou fecho de continuidade).
   * Query params opcionais: anoLetivo, disciplinaId
   */
  app.get("/api/disciplinas/alunos-prova", requireAuth, async (req: Request, res: Response) => {
    try {
      const { anoLetivo, disciplinaId } = req.query as Record<string, string | undefined>;
      const cfgRows = await query<{ notaMinimaAprovacao: unknown }>(`SELECT "notaMinimaAprovacao" FROM public.config_geral LIMIT 1`);
      const notaMin = Number(cfgRows[0]?.notaMinimaAprovacao ?? 10);

      const rows = await query<{
        alunoId: string; alunoNome: string; turmaNome: string;
        classe: string; anoLetivo: string; disciplina: string;
        tipoDisciplina: string; classeFim: string; mediaAnual: string;
      }>(`
        SELECT
          a.id                                         AS "alunoId",
          TRIM(a.nome || ' ' || COALESCE(a.apelido,'')) AS "alunoNome",
          t.nome                                       AS "turmaNome",
          t.classe,
          t."anoLetivo",
          d.nome                                       AS "disciplina",
          d.tipo                                       AS "tipoDisciplina",
          d."classeFim",
          ROUND(AVG(n.nf)::numeric,2)::text            AS "mediaAnual"
        FROM public.notas n
        JOIN public.alunos a  ON a.id  = n."alunoId"
        JOIN public.turmas t  ON t.id  = n."turmaId"
        JOIN public.disciplinas d ON d.nome = n.disciplina AND d.ativo = true
        WHERE a.ativo = true
          AND d."classeFim" != ''
          AND (
            t.classe = d."classeFim"
            OR (
              d."classeFim" NOT IN ('Iniciação','')
              AND t.classe NOT IN ('Iniciação','')
              AND regexp_replace(d."classeFim", '[^0-9]','','g') != ''
              AND regexp_replace(t.classe, '[^0-9]','','g') != ''
              AND regexp_replace(d."classeFim", '[^0-9]','','g') = regexp_replace(t.classe, '[^0-9]','','g')
            )
          )
          AND ($1::text IS NULL OR t."anoLetivo" = $1)
          AND ($2::text IS NULL OR d.id::text = $2)
        GROUP BY a.id, a.nome, a.apelido, t.nome, t.classe, t."anoLetivo", d.nome, d.tipo, d."classeFim"
        HAVING ROUND(AVG(n.nf)::numeric,0) < $3
        ORDER BY t.classe, t.nome, a.apelido, a.nome
      `, [anoLetivo ?? null, disciplinaId ?? null, notaMin]);

      json(res, 200, { notaMin, total: rows.length, alunos: rows });
    } catch (e) { json(res, 500, { error: (e as Error).message }); }
  });

  /**
   * POST /api/disciplinas/alunos-prova/notificar
   * Envia notificação in-app aos encarregados dos alunos identificados.
   * Body (opcional): { anoLetivo, disciplinaId, mensagemExtra }
   */
  app.post("/api/disciplinas/alunos-prova/notificar", requireAuth, async (req: Request, res: Response) => {
    try {
      const b = req.body as Record<string, string | undefined> ?? {};
      const { anoLetivo, disciplinaId, mensagemExtra } = b;
      const cfgRows = await query<{ notaMinimaAprovacao: unknown }>(`SELECT "notaMinimaAprovacao" FROM public.config_geral LIMIT 1`);
      const notaMin = Number(cfgRows[0]?.notaMinimaAprovacao ?? 10);

      const alunosRows = await query<{
        alunoId: string; alunoNome: string; disciplina: string;
        classe: string; anoLetivo: string; mediaAnual: string;
      }>(`
        SELECT
          a.id                                         AS "alunoId",
          TRIM(a.nome || ' ' || COALESCE(a.apelido,'')) AS "alunoNome",
          d.nome                                       AS "disciplina",
          t.classe,
          t."anoLetivo",
          ROUND(AVG(n.nf)::numeric,2)::text            AS "mediaAnual"
        FROM public.notas n
        JOIN public.alunos a  ON a.id  = n."alunoId"
        JOIN public.turmas t  ON t.id  = n."turmaId"
        JOIN public.disciplinas d ON d.nome = n.disciplina AND d.ativo = true
        WHERE a.ativo = true
          AND d."classeFim" != ''
          AND (
            t.classe = d."classeFim"
            OR (
              d."classeFim" NOT IN ('Iniciação','')
              AND t.classe NOT IN ('Iniciação','')
              AND regexp_replace(d."classeFim", '[^0-9]','','g') != ''
              AND regexp_replace(t.classe, '[^0-9]','','g') != ''
              AND regexp_replace(d."classeFim", '[^0-9]','','g') = regexp_replace(t.classe, '[^0-9]','','g')
            )
          )
          AND ($1::text IS NULL OR t."anoLetivo" = $1)
          AND ($2::text IS NULL OR d.id::text = $2)
        GROUP BY a.id, a.nome, a.apelido, d.nome, t.classe, t."anoLetivo"
        HAVING ROUND(AVG(n.nf)::numeric,0) < $3
        ORDER BY a.apelido, a.nome
      `, [anoLetivo ?? null, disciplinaId ?? null, notaMin]);

      if (!alunosRows.length) return json(res, 200, { ok: true, enviadas: 0 });

      // Dados da escola para o email
      const cfgNotif = await query<{ nomeEscola: unknown }>(`SELECT "nomeEscola" FROM public.config_geral LIMIT 1`);
      const nomeEscola = String(cfgNotif[0]?.nomeEscola ?? 'Super Escola');

      // Para cada aluno, buscar encarregado e inserir notificação in-app + email
      let enviadas = 0;
      for (const al of alunosRows) {
        // Encarregados com conta no sistema (role='encarregado' + alunoId)
        const encarregados = await query<{ utilizadorId: string; emailUtil: string | null; nomeUtil: string | null }>(
          `SELECT u.id AS "utilizadorId", u.email AS "emailUtil", u.nome AS "nomeUtil"
           FROM public.utilizadores u
           WHERE u."alunoId" = $1 AND u.role = 'encarregado' AND u.ativo = true`,
          [al.alunoId]
        );
        // Email directo no registo do aluno (encarregado sem conta)
        const alunoExtra = await query<{ emailEncarregado: string | null; nomeEncarregado: string | null }>(
          `SELECT "emailEncarregado", "nomeEncarregado" FROM public.alunos WHERE id=$1`, [al.alunoId]
        );

        const titulo = `Aluno a exame — ${al.disciplina}`;
        const msg = `O(a) aluno(a) ${al.alunoNome} (${al.classe}, ${al.anoLetivo}) tem média de ${parseFloat(al.mediaAnual).toFixed(1)} valores em ${al.disciplina} e está sujeito(a) a exame de recuperação.${mensagemExtra ? ' ' + mensagemExtra : ''}`;

        for (const enc of encarregados) {
          // Notificação in-app
          await query(
            `INSERT INTO public.notificacoes ("utilizadorId","titulo","mensagem","tipo","data","lida","link")
             VALUES ($1,$2,$3,'aviso',NOW(),false,'/notas')`,
            [enc.utilizadorId, titulo, msg]
          );
          // Email se Resend configurado
          if (enc.emailUtil && process.env.RESEND_API_KEY) {
            try {
              const { sendGuardianNotificationEmail } = await import('./email');
              await sendGuardianNotificationEmail(enc.emailUtil, enc.nomeUtil || 'Encarregado', titulo, msg, 'nota', al.alunoNome, nomeEscola);
            } catch {}
          }
          enviadas++;
        }

        // Email directo no registo do aluno (sem conta no sistema)
        const emailDireto = alunoExtra[0]?.emailEncarregado;
        const nomeDireto = alunoExtra[0]?.nomeEncarregado;
        if (emailDireto && process.env.RESEND_API_KEY) {
          // Só envia se não foi já coberto pelos encarregados com conta
          const jaEnviado = encarregados.some(e => e.emailUtil === emailDireto);
          if (!jaEnviado) {
            try {
              const { sendGuardianNotificationEmail } = await import('./email');
              await sendGuardianNotificationEmail(emailDireto, nomeDireto || 'Encarregado', titulo, msg, 'nota', al.alunoNome, nomeEscola);
            } catch {}
          }
        }
      }

      json(res, 200, { ok: true, enviadas, alunosAfetados: alunosRows.length });
    } catch (e) { json(res, 500, { error: (e as Error).message }); }
  });

  /**
   * GET /api/disciplinas/alunos-prova/html
   * Devolve uma página HTML imprimível com a lista de alunos sujeitos a exame.
   * Query params opcionais: anoLetivo, disciplinaId
   */
  app.get("/api/disciplinas/alunos-prova/html", async (req: Request, res: Response) => {
    try {
      // Aceita token via query param (navegação directa/nova aba) ou Authorization header
      const qToken = req.query.token as string | undefined;
      const authHdr = req.headers.authorization;
      let tok: any = null;
      if (qToken) tok = verifyToken(qToken);
      else if (authHdr?.startsWith('Bearer ')) tok = verifyToken(authHdr.slice(7));
      if (!tok) return res.status(401).json({ error: 'Não autenticado. Faça login para continuar.' });

      const { anoLetivo, disciplinaId } = req.query as Record<string, string | undefined>;
      const cfgRows = await query<{ notaMinimaAprovacao: unknown; nomeEscola: unknown }>(`SELECT "notaMinimaAprovacao", "nomeEscola" FROM public.config_geral LIMIT 1`);
      const notaMin = Number(cfgRows[0]?.notaMinimaAprovacao ?? 10);
      const nomeEscola = String(cfgRows[0]?.nomeEscola ?? 'Escola');

      const rows = await query<{
        alunoNome: string; turmaNome: string; classe: string;
        anoLetivo: string; disciplina: string; tipoDisciplina: string; mediaAnual: string;
      }>(`
        SELECT
          TRIM(a.nome || ' ' || COALESCE(a.apelido,'')) AS "alunoNome",
          t.nome                                         AS "turmaNome",
          t.classe,
          t."anoLetivo",
          d.nome                                         AS "disciplina",
          d.tipo                                         AS "tipoDisciplina",
          ROUND(AVG(n.nf)::numeric,2)::text              AS "mediaAnual"
        FROM public.notas n
        JOIN public.alunos a  ON a.id  = n."alunoId"
        JOIN public.turmas t  ON t.id  = n."turmaId"
        JOIN public.disciplinas d ON d.nome = n.disciplina AND d.ativo = true
        WHERE a.ativo = true
          AND d."classeFim" != ''
          AND (
            t.classe = d."classeFim"
            OR (
              d."classeFim" NOT IN ('Iniciação','')
              AND t.classe NOT IN ('Iniciação','')
              AND regexp_replace(d."classeFim", '[^0-9]','','g') != ''
              AND regexp_replace(t.classe, '[^0-9]','','g') != ''
              AND regexp_replace(d."classeFim", '[^0-9]','','g') = regexp_replace(t.classe, '[^0-9]','','g')
            )
          )
          AND ($1::text IS NULL OR t."anoLetivo" = $1)
          AND ($2::text IS NULL OR d.id::text = $2)
        GROUP BY a.nome, a.apelido, t.nome, t.classe, t."anoLetivo", d.nome, d.tipo
        HAVING ROUND(AVG(n.nf)::numeric,0) < $3
        ORDER BY t.classe, t.nome, a.apelido, a.nome
      `, [anoLetivo ?? null, disciplinaId ?? null, notaMin]);

      const dataHoje = new Date().toLocaleDateString('pt-AO', { day: '2-digit', month: 'long', year: 'numeric' });
      const filtroAno = anoLetivo ? `Ano Lectivo: ${anoLetivo}` : 'Todos os anos lectivos';

      let linhas = '';
      rows.forEach((r, i) => {
        const tipo = r.tipoDisciplina === 'terminal' ? 'Terminal' : 'Continuidade';
        linhas += `
          <tr class="${i % 2 === 0 ? 'par' : 'impar'}">
            <td>${i + 1}</td>
            <td>${r.alunoNome}</td>
            <td>${r.classe}</td>
            <td>${r.turmaNome}</td>
            <td>${r.anoLetivo}</td>
            <td>${r.disciplina}</td>
            <td class="center"><span class="badge ${r.tipoDisciplina}">${tipo}</span></td>
            <td class="center negativa">${parseFloat(r.mediaAnual).toFixed(1)}</td>
            <td></td>
          </tr>`;
      });

      const html = `<!DOCTYPE html>
<html lang="pt">
<head>
<meta charset="UTF-8">
<title>Lista de Alunos Sujeitos a Exame</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body { font-family: Arial, sans-serif; font-size: 11px; color: #1a1a1a; padding: 24px; }
  h1 { font-size: 15px; text-align: center; margin-bottom: 2px; }
  h2 { font-size: 12px; text-align: center; font-weight: normal; color: #555; margin-bottom: 16px; }
  .meta { display: flex; justify-content: space-between; margin-bottom: 12px; font-size: 10px; color: #666; }
  table { width: 100%; border-collapse: collapse; }
  th { background: #1a3a5c; color: #fff; padding: 6px 8px; text-align: left; font-size: 10px; }
  td { padding: 5px 8px; border-bottom: 1px solid #e5e7eb; }
  tr.par td { background: #f8fafc; }
  tr.impar td { background: #fff; }
  .center { text-align: center; }
  .negativa { color: #dc2626; font-weight: bold; }
  .badge { display: inline-block; padding: 2px 7px; border-radius: 10px; font-size: 9px; font-weight: bold; }
  .badge.terminal { background: #fee2e2; color: #dc2626; }
  .badge.continuidade { background: #dbeafe; color: assinatura: #1d4ed8; }
  .rodape { margin-top: 24px; display: flex; justify-content: space-between; align-items: flex-end; }
  .assinatura { text-align: center; border-top: 1px solid #999; padding-top: 4px; min-width: 200px; font-size: 10px; color: #555; }
  @media print { body { padding: 10px; } }
</style>
</head>
<body>
  <h1>${nomeEscola}</h1>
  <h2>Lista de Alunos Sujeitos a Exame de Recuperação / Época Normal</h2>
  <div class="meta">
    <span>${filtroAno}</span>
    <span>Nota mínima de aprovação: <strong>${notaMin} valores</strong></span>
    <span>Total: <strong>${rows.length} aluno(s)</strong></span>
    <span>Emitido em: ${dataHoje}</span>
  </div>
  <table>
    <thead>
      <tr>
        <th>#</th>
        <th>Nome do Aluno</th>
        <th>Classe</th>
        <th>Turma</th>
        <th>Ano Lectivo</th>
        <th>Disciplina</th>
        <th class="center">Tipo</th>
        <th class="center">Média</th>
        <th>Observações</th>
      </tr>
    </thead>
    <tbody>
      ${linhas || '<tr><td colspan="9" style="text-align:center;padding:16px;color:#6b7280;">Nenhum aluno sujeito a exame encontrado.</td></tr>'}
    </tbody>
  </table>
  <div class="rodape">
    <div class="assinatura">Director(a) Pedagógico(a)</div>
    <div class="assinatura">Director(a) Geral</div>
  </div>
</body>
</html>`;

      res.setHeader('Content-Type', 'text/html; charset=utf-8');
      res.send(html);
    } catch (e) { json(res, 500, { error: (e as Error).message }); }
  });

  app.get("/api/provincias", async (_req: Request, res: Response) => {
    try {
      const rows = await query<JsonObject>(`SELECT id, nome FROM public.provincias ORDER BY nome ASC`, []);
      json(res, 200, rows);
    } catch (e) { json(res, 500, { error: (e as Error).message }); }
  });

  app.get("/api/municipios", async (req: Request, res: Response) => {
    try {
      const { provinciaId } = req.query;
      if (!provinciaId) return json(res, 400, { error: 'provinciaId é obrigatório.' });
      const rows = await query<JsonObject>(
        `SELECT id, nome, "provinciaId" FROM public.municipios WHERE "provinciaId"=$1 ORDER BY nome ASC`,
        [Number(provinciaId)]
      );
      json(res, 200, rows);
    } catch (e) { json(res, 500, { error: (e as Error).message }); }
  });

  // -----------------------
  // RECUPERAÇÃO DE SENHA
  // -----------------------

  // Endpoint público: verificar se o email existe e retornar dica do nome (sem autenticação)
  app.post("/api/public/check-email-reset", async (req: Request, res: Response) => {
    try {
      const b = requireBodyObject(req);
      const email = String(b.email ?? "").toLowerCase().trim();
      if (!email) return json(res, 400, { error: "Email é obrigatório." });
      const FIXED = ["ceo@sige.ao","financeiro@sige.ao","secretaria@sige.ao","rh@sige.ao"];
      if (FIXED.includes(email)) {
        return json(res, 400, { error: "Esta conta de sistema só pode ser redefinida pelo administrador." });
      }
      const rows = await query<JsonObject>(
        `SELECT nome FROM public.utilizadores WHERE LOWER(email)=LOWER($1) AND ativo=true LIMIT 1`,
        [email]
      );
      if (!rows[0]) {
        // Por segurança, não revelar se o email existe
        return json(res, 200, { encontrado: false });
      }
      // Retornar apenas o primeiro nome como dica
      const nomeCompleto = String(rows[0].nome).trim();
      const primeiroNome = nomeCompleto.split(' ')[0];
      return json(res, 200, { encontrado: true, dica: primeiroNome });
    } catch (e) {
      console.error("[check-email-reset]", e);
      return json(res, 500, { error: "Erro interno." });
    }
  });

  // Endpoint público: redefinir senha sem email (verificação por nome completo)
  app.post("/api/public/reset-senha-direto", async (req: Request, res: Response) => {
    try {
      const b = requireBodyObject(req);
      const email = String(b.email ?? "").toLowerCase().trim();
      const nomeVerificacao = String(b.nomeVerificacao ?? "").trim();
      const novaSenha = String(b.novaSenha ?? "").trim();

      if (!email || !nomeVerificacao || !novaSenha) {
        return json(res, 400, { error: "Todos os campos são obrigatórios." });
      }
      if (novaSenha.length < 6) {
        return json(res, 400, { error: "A senha deve ter pelo menos 6 caracteres." });
      }

      const rows = await query<JsonObject>(
        `SELECT id, nome FROM public.utilizadores WHERE LOWER(email)=LOWER($1) AND ativo=true LIMIT 1`,
        [email]
      );
      if (!rows[0]) {
        return json(res, 404, { error: "Utilizador não encontrado." });
      }
      const nomeDB = String(rows[0].nome).trim().toLowerCase();
      const nomeInput = nomeVerificacao.trim().toLowerCase();
      // Verificar: o nome introduzido deve ser encontrado no nome completo registado
      if (!nomeDB.includes(nomeInput) && !nomeInput.includes(nomeDB.split(' ')[0])) {
        return json(res, 401, { error: "Nome não corresponde ao registado nesta conta." });
      }

      await query(
        `UPDATE public.utilizadores SET senha=$1 WHERE LOWER(email)=LOWER($2) AND ativo=true`,
        [novaSenha, email]
      );
      return json(res, 200, { ok: true });
    } catch (e) {
      console.error("[reset-senha-direto]", e);
      return json(res, 500, { error: "Erro interno." });
    }
  });

  app.post("/api/forgot-password", async (req: Request, res: Response) => {
    try {
      const b = requireBodyObject(req);
      const email = String(b.email ?? "").toLowerCase().trim();
      if (!email) return json(res, 400, { error: "Email é obrigatório." });

      // Verificar se o email existe (utilizadores da BD ou contas fixas)
      const FIXED_EMAILS = [
        "ceo@sige.ao", "financeiro@sige.ao", "secretaria@sige.ao", "rh@sige.ao"
      ];
      let nomeUtilizador = "";

      if (FIXED_EMAILS.includes(email)) {
        return json(res, 400, {
          error: "Este email pertence a uma conta de sistema. Contacte o administrador para redefinir a senha."
        });
      }

      const rows = await query<JsonObject>(
        `SELECT id, nome, email FROM public.utilizadores WHERE LOWER(email)=LOWER($1) AND ativo=true LIMIT 1`,
        [email]
      );
      if (!rows[0]) {
        // Por segurança, responder com sucesso mesmo que o email não exista
        return json(res, 200, { ok: true, message: "Se o email existir no sistema, receberá um link de redefinição." });
      }
      nomeUtilizador = String(rows[0].nome);

      // Invalidar tokens anteriores deste email
      await query(
        `UPDATE public.password_reset_tokens SET "usedAt"=NOW() WHERE email=LOWER($1) AND "usedAt" IS NULL`,
        [email]
      );

      // Gerar novo token seguro
      const token = crypto.randomBytes(32).toString("hex");
      const expiresAt = new Date(Date.now() + 60 * 60 * 1000); // 1 hora

      await query(
        `INSERT INTO public.password_reset_tokens (email, token, "expiresAt") VALUES (LOWER($1), $2, $3)`,
        [email, token, expiresAt.toISOString()]
      );

      // Construir link de reset
      let appDomain = "";
      if (process.env.REPLIT_DOMAINS) {
        appDomain = `https://${process.env.REPLIT_DOMAINS.split(",")[0].trim()}`;
      } else if (process.env.REPLIT_DEV_DOMAIN) {
        appDomain = `https://${process.env.REPLIT_DEV_DOMAIN}`;
      } else {
        appDomain = `http://localhost:5000`;
      }
      const resetLink = `${appDomain}/redefinir-senha?token=${token}`;

      let nomeEscola: string | undefined;
      try {
        const cfgRows = await query<JsonObject>(`SELECT "nomeEscola" FROM public.config_geral LIMIT 1`, []);
        if (cfgRows[0]?.nomeEscola) nomeEscola = String(cfgRows[0].nomeEscola);
      } catch { /* sem configuração disponível */ }

      const result = await sendPasswordResetEmail(email, nomeUtilizador, resetLink, nomeEscola);

      if (!result.success) {
        return json(res, 500, { error: result.message });
      }

      return json(res, 200, { ok: true, message: "Link de redefinição enviado para o seu email." });
    } catch (e) {
      console.error("[forgot-password]", e);
      return json(res, 500, { error: "Erro interno. Tente novamente mais tarde." });
    }
  });

  app.post("/api/reset-password", async (req: Request, res: Response) => {
    try {
      const b = requireBodyObject(req);
      const token = String(b.token ?? "").trim();
      const novaSenha = String(b.novaSenha ?? "").trim();

      if (!token || !novaSenha) {
        return json(res, 400, { error: "Token e nova senha são obrigatórios." });
      }
      if (novaSenha.length < 6) {
        return json(res, 400, { error: "A senha deve ter pelo menos 6 caracteres." });
      }

      // Verificar token
      const tokenRows = await query<JsonObject>(
        `SELECT * FROM public.password_reset_tokens WHERE token=$1 AND "usedAt" IS NULL AND "expiresAt" > NOW() LIMIT 1`,
        [token]
      );
      if (!tokenRows[0]) {
        return json(res, 400, { error: "Link inválido ou expirado. Solicite um novo link de redefinição." });
      }

      const tokenRecord = tokenRows[0];
      const email = String(tokenRecord.email);

      // Atualizar senha do utilizador
      const updateRows = await query<JsonObject>(
        `UPDATE public.utilizadores SET senha=$1 WHERE LOWER(email)=LOWER($2) AND ativo=true RETURNING id`,
        [novaSenha, email]
      );
      if (!updateRows[0]) {
        return json(res, 404, { error: "Utilizador não encontrado ou inactivo." });
      }

      // Marcar token como usado
      await query(
        `UPDATE public.password_reset_tokens SET "usedAt"=NOW() WHERE token=$1`,
        [token]
      );

      return json(res, 200, { ok: true, message: "Senha redefinida com sucesso. Pode agora iniciar sessão." });
    } catch (e) {
      console.error("[reset-password]", e);
      return json(res, 500, { error: "Erro interno. Tente novamente mais tarde." });
    }
  });

  app.get("/api/verify-reset-token", async (req: Request, res: Response) => {
    try {
      const token = String(req.query.token ?? "").trim();
      if (!token) return json(res, 400, { error: "Token é obrigatório." });

      const rows = await query<JsonObject>(
        `SELECT email FROM public.password_reset_tokens WHERE token=$1 AND "usedAt" IS NULL AND "expiresAt" > NOW() LIMIT 1`,
        [token]
      );
      if (!rows[0]) {
        return json(res, 400, { valid: false, error: "Link inválido ou expirado." });
      }
      return json(res, 200, { valid: true, email: String(rows[0].email) });
    } catch (e) {
      return json(res, 500, { error: (e as Error).message });
    }
  });

  // ─── VERIFICAÇÃO OTP — LOGIN ─────────────────────────────────────────────────
  app.post("/api/auth/otp/verificar-login", async (req: Request, res: Response) => {
    try {
      const b = requireBodyObject(req);
      const email  = String(b.email  ?? '').toLowerCase().trim();
      const codigo = String(b.codigo ?? '').replace(/\D/g, '').trim();
      if (!email || codigo.length !== 6) {
        return json(res, 400, { error: 'Email e código de 6 dígitos são obrigatórios.' });
      }
      const result = verifyOtp('login', email, codigo);
      if (!result.ok) {
        const msgs: Record<string, string> = {
          'not-found':         'Código não encontrado. Faça login novamente para receber um novo código.',
          'expired':           'Código expirado. Faça login novamente para receber um novo código.',
          'too-many-attempts': 'Demasiadas tentativas. Faça login novamente.',
          'wrong-code':        'Código incorrecto. Verifique e tente novamente.',
        };
        return json(res, 401, { error: msgs[result.reason ?? ''] ?? 'Código inválido.' });
      }
      const rows = await query<JsonObject>(
        `SELECT * FROM public.utilizadores WHERE id=$1 AND ativo=true LIMIT 1`,
        [result.userId!]
      );
      if (!rows[0]) return json(res, 404, { error: 'Utilizador não encontrado ou inactivo.' });
      const u = rows[0];
      const ip = req.headers['x-forwarded-for']?.toString().split(',')[0] ?? req.socket?.remoteAddress;
      const ua = req.headers['user-agent'];
      const cursoIdToken = u.cursoId ? String(u.cursoId) : undefined;
      const token = signToken({ userId: String(u.id), role: String(u.role) as UserRole, email: String(u.email), ...(cursoIdToken ? { cursoId: cursoIdToken } : {}) });
      logAudit({
        userId: String(u.id), userEmail: String(u.email), userRole: String(u.role), userName: String(u.nome),
        acao: 'otp_login_verificado', modulo: 'Autenticação',
        descricao: `Login com verificação OTP concluído: ${u.email}`,
        ipAddress: ip, userAgent: ua,
      }).catch(() => {});
      let alunoId: string | null = null; let genero = ''; let dataNascimento = '';
      if (String(u.role) === 'aluno') {
        const ar = await query<JsonObject>(`SELECT id,genero,"dataNascimento" FROM public.alunos WHERE "utilizadorId"=$1 LIMIT 1`, [String(u.id)]);
        if (ar[0]) { alunoId = String(ar[0].id); genero = String(ar[0].genero??''); dataNascimento = String(ar[0].dataNascimento??''); }
      } else {
        const fr = await query<JsonObject>(`SELECT genero,"dataNascimento" FROM public.funcionarios WHERE "utilizadorId"=$1 LIMIT 1`, [String(u.id)]);
        if (fr[0]) { genero = String(fr[0].genero??''); dataNascimento = String(fr[0].dataNascimento??''); }
      }
      let avatar = String(u.avatar ?? '');
      if (!avatar && String(u.role) === 'aluno' && alunoId) {
        const ar2 = await query<JsonObject>(`SELECT foto FROM public.alunos WHERE id=$1 LIMIT 1`, [alunoId]);
        avatar = String(ar2[0]?.foto ?? '');
      }
      const cfgE2 = await query<JsonObject>(`SELECT "nomeEscola" FROM public.config_geral LIMIT 1`).catch(() => [] as JsonObject[]);
      const escolaOtp = String((cfgE2 as JsonObject[])[0]?.nomeEscola ?? u.escola ?? 'SIGA');
      const jaPrimeiroLogin = u.primeiroLogin === true || u.primeiroLogin === 'true';
      registerSession({ userId: String(u.id), role: String(u.role), email: String(u.email), nome: String(u.nome??''), ip: ip??'', userAgent: ua??'', loginAt: Date.now(), lastSeen: Date.now(), avatar });
      return json(res, 200, {
        token,
        primeiroAcesso: !jaPrimeiroLogin,
        user: { id: u.id, nome: u.nome, email: u.email, role: u.role, escola: escolaOtp, telefone: u.telefone??'', avatar, genero, dataNascimento, ...(alunoId?{alunoId}:{}), ...(u.cursoId?{cursoId:String(u.cursoId)}:{}) }
      });
    } catch (e) {
      console.error('[otp/verificar-login]', e);
      return json(res, 500, { error: 'Erro interno. Tente novamente mais tarde.' });
    }
  });

  // ─── OTP — RECUPERAÇÃO DE SENHA ──────────────────────────────────────────────
  app.post("/api/auth/otp/recuperacao/enviar", async (req: Request, res: Response) => {
    try {
      const b = requireBodyObject(req);
      const email = String(b.email ?? '').toLowerCase().trim();
      if (!email) return json(res, 400, { error: 'Email é obrigatório.' });
      const FIXED = ['ceo@sige.ao','financeiro@sige.ao','secretaria@sige.ao','rh@sige.ao'];
      if (FIXED.includes(email)) {
        return json(res, 400, { error: 'Esta conta de sistema só pode ser redefinida pelo administrador.' });
      }
      const rows = await query<JsonObject>(
        `SELECT id, nome, email, telefone FROM public.utilizadores WHERE LOWER(email)=LOWER($1) AND ativo=true LIMIT 1`,
        [email]
      );
      if (!rows[0]) {
        return json(res, 200, { enviado: false, semConta: true });
      }
      const u = rows[0];
      if (!canResendOtp('recovery', email)) {
        return json(res, 200, { enviado: true, tooSoon: true, emailEnviado: true });
      }
      const otpCode = generateOtp('recovery', email, String(u.id));
      let nomeEscola2 = 'SIGA';
      try {
        const cfg2 = await query<JsonObject>(`SELECT "nomeEscola" FROM public.config_geral LIMIT 1`);
        if (cfg2[0]?.nomeEscola) nomeEscola2 = String(cfg2[0].nomeEscola);
      } catch {}
      // Recuperação sempre por email
      const emailResult = await sendOtpByEmail(String(u.email), String(u.nome || ''), otpCode, nomeEscola2);
      if (!emailResult.success) {
        console.error('[otp/recuperacao/enviar] Falha ao enviar email:', emailResult.message);
        // mostrar código na consola como fallback
        console.log(`[OTP RECUPERACAO] Email: ${u.email} | Código: ${otpCode}`);
      } else {
        console.log(`[otp/recuperacao/enviar] Email enviado com sucesso para ${String(u.email)} via ${process.env.EMAIL_FROM}`);
      }
      return json(res, 200, { enviado: true, emailEnviado: true, email: String(u.email).replace(/(.{2})(.*)(@.*)/, '$1***$3') });
    } catch (e) {
      console.error('[otp/recuperacao/enviar]', e);
      return json(res, 500, { error: 'Erro interno. Tente novamente mais tarde.' });
    }
  });

  app.post("/api/auth/otp/recuperacao/verificar", async (req: Request, res: Response) => {
    try {
      const b = requireBodyObject(req);
      const email  = String(b.email  ?? '').toLowerCase().trim();
      const codigo = String(b.codigo ?? '').replace(/\D/g, '').trim();
      if (!email || codigo.length !== 6) {
        return json(res, 400, { error: 'Email e código de 6 dígitos são obrigatórios.' });
      }
      const result = verifyOtp('recovery', email, codigo);
      if (!result.ok) {
        const msgs: Record<string, string> = {
          'not-found':         'Código não encontrado. Solicite um novo código.',
          'expired':           'Código expirado. Solicite um novo código.',
          'too-many-attempts': 'Demasiadas tentativas. Solicite um novo código.',
          'wrong-code':        'Código incorrecto. Verifique e tente novamente.',
        };
        return json(res, 401, { error: msgs[result.reason ?? ''] ?? 'Código inválido.' });
      }
      const recoveryToken = createRecoveryToken(email);
      return json(res, 200, { ok: true, recoveryToken });
    } catch (e) {
      console.error('[otp/recuperacao/verificar]', e);
      return json(res, 500, { error: 'Erro interno. Tente novamente mais tarde.' });
    }
  });

  app.post("/api/auth/otp/recuperacao/nova-senha", async (req: Request, res: Response) => {
    try {
      const b = requireBodyObject(req);
      const recoveryToken = String(b.recoveryToken ?? '').trim();
      const novaSenha     = String(b.novaSenha     ?? '').trim();
      if (!recoveryToken || !novaSenha) {
        return json(res, 400, { error: 'Token de recuperação e nova senha são obrigatórios.' });
      }
      if (novaSenha.length < 6) {
        return json(res, 400, { error: 'A senha deve ter pelo menos 6 caracteres.' });
      }
      const tokenResult = consumeRecoveryToken(recoveryToken);
      if (!tokenResult.ok) {
        return json(res, 400, { error: 'Sessão de recuperação expirada ou inválida. Por favor, reinicie o processo.' });
      }
      const bcryptOtp = await import('bcryptjs');
      const senhaHash = await bcryptOtp.hash(novaSenha, 10);
      const updated = await query<JsonObject>(
        `UPDATE public.utilizadores SET senha=$1 WHERE LOWER(email)=LOWER($2) AND ativo=true RETURNING id`,
        [senhaHash, tokenResult.email!]
      );
      if (!updated[0]) return json(res, 404, { error: 'Utilizador não encontrado.' });
      logAudit({
        userId: String(updated[0].id), userEmail: tokenResult.email!, userRole: 'desconhecido',
        acao: 'senha_redefinida_otp', modulo: 'Autenticação',
        descricao: `Senha redefinida via código OTP: ${tokenResult.email}`,
      }).catch(() => {});
      return json(res, 200, { ok: true, message: 'Senha redefinida com sucesso.' });
    } catch (e) {
      console.error('[otp/recuperacao/nova-senha]', e);
      return json(res, 500, { error: 'Erro interno. Tente novamente mais tarde.' });
    }
  });

  // ─── TELEGRAM BOT — OTP E LIGAÇÃO DE CONTA ──────────────────────────────────

  // GET /api/telegram/status — verifica se o utilizador tem Telegram ligado
  app.get("/api/telegram/status", requireAuth, async (req: Request, res: Response) => {
    try {
      const userId = req.jwtUser?.userId;
      if (!userId) return json(res, 401, { error: 'Não autenticado.' });
      const rows = await query<{ telegramChatId: string | null }>(
        `SELECT "telegramChatId" FROM public.utilizadores WHERE id=$1 LIMIT 1`, [userId]
      );
      const chatId = rows[0]?.telegramChatId || null;
      return json(res, 200, {
        linked: !!chatId,
        botUsername: getTelegramBotUsername(),
        configured: isTelegramConfigured(),
      });
    } catch (e) {
      return json(res, 500, { error: (e as Error).message });
    }
  });

  // POST /api/telegram/link — gera deep link para ligar conta ao Telegram
  // Também aceita ?token= na query string como fallback (para clientes que não conseguem enviar Authorization header)
  app.post("/api/telegram/link", (req: Request, res: Response, next: NextFunction) => {
    // Log de diagnóstico temporário
    const authHeader = req.headers['authorization'] || '';
    const hasAuth = authHeader.startsWith('Bearer ') && authHeader.length > 10;
    console.log(`[telegram/link] Authorization header: ${hasAuth ? 'PRESENTE' : 'AUSENTE'} (${authHeader.slice(0,30) || 'vazio'})`);
    next();
  }, requireAuth, async (req: Request, res: Response) => {
    try {
      if (!isTelegramConfigured()) {
        return json(res, 503, { error: 'Telegram Bot não configurado no servidor. Contacte o administrador.' });
      }
      const botUsername = getTelegramBotUsername();
      if (!botUsername) {
        return json(res, 503, { error: 'TELEGRAM_BOT_USERNAME não configurado no servidor.' });
      }
      const userId = req.jwtUser?.userId;
      if (!userId) return json(res, 401, { error: 'Não autenticado.' });
      const token = createTelegramLinkToken(userId);
      const url = `https://t.me/${botUsername}?start=${token}`;
      console.log(`[telegram/link] ✅ Link gerado para userId=${userId} → ${url}`);
      return json(res, 200, { url, token, botUsername });
    } catch (e) {
      return json(res, 500, { error: (e as Error).message });
    }
  });

  // DELETE /api/telegram/unlink — desliga conta do Telegram
