  // POST /api/telegram/webhook — recebe mensagens do Telegram Bot (sem auth JWT — chamado pelo Telegram)
  app.post("/api/telegram/webhook", async (req: Request, res: Response) => {
    try {
      const body = req.body as any;
      const message = body?.message;
      if (!message?.text || !message?.chat?.id) return res.sendStatus(200);

      const chatId = String(message.chat.id);
      const text = (message.text as string).trim();

      // Processar /start TOKEN (ligação de conta)
      const startMatch = text.match(/^\/start\s+([a-f0-9]{32})$/i);
      if (startMatch) {
        const token = startMatch[1];
        const userId = consumeTelegramLinkToken(token);
        if (!userId) {
          await sendTelegramMessage(chatId, '❌ Link expirado ou inválido.\n\nGere um novo link no *Perfil → Segurança → Ligar Telegram* no SIGA.');
          return res.sendStatus(200);
        }
        await query(`UPDATE public.utilizadores SET "telegramChatId"=$1 WHERE id=$2`, [chatId, userId]);
        const userRows = await query<{ nome: string; email: string; role: string }>(
          `SELECT nome, email, role FROM public.utilizadores WHERE id=$1 LIMIT 1`, [userId]
        );
        const nome = (userRows[0]?.nome || 'Utilizador').split(' ')[0];
        await sendTelegramMessage(chatId,
          `✅ *Olá, ${nome}!*\n\n` +
          `O seu Telegram foi ligado com sucesso ao *SIGA*.\n\n` +
          `A partir de agora, os seus códigos de verificação (OTP) serão enviados aqui.\n\n` +
          `🔐 _Conta segura e protegida._`
        );
        logAudit({
          userId, userEmail: userRows[0]?.email || '', userRole: userRows[0]?.role || '',
          acao: 'telegram_ligado', modulo: 'Segurança',
          descricao: `Conta Telegram ligada com sucesso (chat: ${chatId}).`,
        }).catch(() => {});
        console.log(`[telegram/webhook] ✅ Conta ${userId} ligada ao Telegram chat ${chatId}`);
        return res.sendStatus(200);
      }

      // /start sem token — mensagem de boas-vindas
      if (text.startsWith('/start')) {
        await sendTelegramMessage(chatId,
          '👋 *Bem-vindo à Super Escola!*\n\n' +
          'Para ligar a sua conta, aceda ao *Perfil* no SIGA e clique em *Segurança → Ligar Telegram*.\n\n' +
          'Após clicar no botão, receberá um link para confirmar a ligação aqui.'
        );
        return res.sendStatus(200);
      }

      // Outros comandos — resposta genérica
      await sendTelegramMessage(chatId,
        '🤖 Este bot envia-lhe os códigos de verificação do SIGA.\n\n' +
        'Para gerir a sua conta, aceda ao SIGA directamente.'
      );
      return res.sendStatus(200);
    } catch (e) {
      console.error('[telegram/webhook]', (e as Error).message);
      return res.sendStatus(200); // Sempre 200 para evitar retransmissões do Telegram
    }
  });

  // POST /api/telegram/setup-webhook — configura o webhook do bot (apenas CEO/admin)
  app.post("/api/telegram/setup-webhook", requireAuth, async (req: Request, res: Response) => {
    try {
      const role = req.jwtUser?.role || '';
      if (!['ceo', 'pca', 'admin'].includes(role)) {
        return json(res, 403, { error: 'Acesso restrito a CEO, PCA e Administradores.' });
      }
      if (!isTelegramConfigured()) {
        return json(res, 503, { error: 'TELEGRAM_BOT_TOKEN não configurado.' });
      }
      const replitDomain = process.env.REPLIT_DEV_DOMAIN || process.env.REPLIT_DOMAINS?.split(',')[0]?.trim();
      const forwardedProto = req.get('x-forwarded-proto') || req.protocol;
      const forwardedHost = req.get('x-forwarded-host') || req.get('host') || '';
      const baseUrl = replitDomain
        ? `https://${replitDomain}`
        : process.env.APP_URL
        || (forwardedHost ? `${forwardedProto}://${forwardedHost}` : `${req.protocol}://${req.get('host')}`);
      const webhookUrl = `${baseUrl}/api/telegram/webhook`;
      const ok = await setTelegramWebhook(webhookUrl);
      return json(res, ok ? 200 : 500, { ok, webhookUrl });
    } catch (e) {
      return json(res, 500, { error: (e as Error).message });
    }
  });

  // POST /api/telegram/link-interno — gera link de ligação para um userId específico (sem JWT, apenas chamada interna)
  // Usado para ligar o CEO ao bot na primeira configuração
  app.post("/api/telegram/link-interno", async (req: Request, res: Response) => {
    try {
      const secret = req.headers['x-internal-secret'] as string;
      if (!secret || secret !== (process.env.JWT_SECRET || '').slice(0, 16)) {
        return json(res, 403, { error: 'Não autorizado.' });
      }
      const { userId } = req.body as { userId: string };
      if (!userId) return json(res, 400, { error: 'userId obrigatório.' });
      if (!isTelegramConfigured()) return json(res, 503, { error: 'Telegram Bot não configurado.' });
      const botUsername = getTelegramBotUsername();
      if (!botUsername) return json(res, 503, { error: 'TELEGRAM_BOT_USERNAME não configurado.' });
      const token = createTelegramLinkToken(userId);
      const url = `https://t.me/${botUsername}?start=${token}`;
      return json(res, 200, { url, token, botUsername });
    } catch (e) {
      return json(res, 500, { error: (e as Error).message });
    }
  });

  // ─── RESET DE SENHA ADMINISTRATIVO ──────────────────────────────────────────
  app.post("/api/admin/reset-user-password", requireAuth, async (req: Request, res: Response) => {
    try {
      const ROLES_PERMITIDAS = ['ceo', 'pca', 'admin', 'director', 'subdirector_pedagogico', 'subdiretor_administrativo', 'chefe_secretaria'];
      const callerRole = req.jwtUser?.role || '';
      if (!ROLES_PERMITIDAS.includes(callerRole)) {
        return json(res, 403, { error: 'Sem permissão. Apenas CEO, PCA, Administrador, Directores e Chefe de Secretaria podem redefinir senhas.' });
      }

      const b = requireBodyObject(req);
      const userId = String(b.userId ?? '').trim();
      if (!userId) return json(res, 400, { error: 'userId é obrigatório.' });

      // Não permite redefinir a própria senha por esta via
      if (req.jwtUser?.userId === userId) {
        return json(res, 400, { error: 'Não pode redefinir a sua própria senha por esta via.' });
      }

      // Buscar o utilizador alvo
      const userRows = await query<JsonObject>(
        `SELECT id, nome, email, role FROM public.utilizadores WHERE id=$1 AND ativo=true LIMIT 1`,
        [userId]
      );
      if (!userRows[0]) return json(res, 404, { error: 'Utilizador não encontrado.' });

      const targetUser = userRows[0];
      const targetRole = String(targetUser.role ?? '');

      // Hierarquia: não pode redefinir senha de alguém com cargo igual ou superior
      const HIERARQUIA = ['ceo', 'pca', 'admin', 'director', 'subdirector_pedagogico', 'subdiretor_administrativo', 'chefe_secretaria'];
      const callerIdx = HIERARQUIA.indexOf(callerRole);
      const targetIdx = HIERARQUIA.indexOf(targetRole);
      if (targetIdx !== -1 && callerIdx !== -1 && targetIdx <= callerIdx && callerRole !== 'ceo' && callerRole !== 'pca') {
        return json(res, 403, { error: 'Não pode redefinir a senha de um utilizador com cargo igual ou superior ao seu.' });
      }

      // Gerar senha temporária segura: Escola + @ + 4 letras maiúsculas + 4 dígitos
      const letras = 'ABCDEFGHJKLMNPQRSTUVWXYZ';
      const digitos = '23456789';
      let tempPart = '';
      for (let i = 0; i < 4; i++) tempPart += letras[Math.floor(Math.random() * letras.length)];
      for (let i = 0; i < 4; i++) tempPart += digitos[Math.floor(Math.random() * digitos.length)];
      const tempPassword = `Escola@${tempPart}`;

      const bcryptLib = await import('bcryptjs');
      const hash = await bcryptLib.hash(tempPassword, 10);

      await query(
        `UPDATE public.utilizadores SET senha=$1 WHERE id=$2`,
        [hash, userId]
      );

      // Registar auditoria
      logAudit({
        userId: String(req.jwtUser?.userId),
        userEmail: String(req.jwtUser?.email),
        userRole: callerRole,
        acao: 'reset_senha_admin',
        modulo: 'Gestão de Acessos',
        descricao: `Senha redefinida para o utilizador: ${String(targetUser.email)} (${String(targetUser.nome)})`,
      }).catch(() => {});

      return json(res, 200, {
        ok: true,
        tempPassword,
        userNome: String(targetUser.nome),
        userEmail: String(targetUser.email),
      });
    } catch (e) {
      console.error('[admin-reset-password]', e);
      return json(res, 500, { error: 'Erro interno. Tente novamente.' });
    }
  });

