  // ── Cadeiras em Atraso por aluno (notas com média final < 10) ────────────────
  app.get('/api/financeiro/cadeiras-atraso', requireAuth, async (req: Request, res: Response) => {
    try {
      const { anoLetivo } = req.query as { anoLetivo?: string };
      if (!anoLetivo) return json(res, 400, { error: 'anoLetivo é obrigatório.' });
      const rows = await query<JsonObject>(`
        SELECT
          n."alunoId",
          COUNT(DISTINCT CASE
            WHEN GREATEST(COALESCE(n.mac,0), COALESCE(n.nf,0)) > 0
             AND GREATEST(COALESCE(n.mac,0), COALESCE(n.nf,0)) < 10
            THEN n.disciplina
          END)::int AS "cadeirasAtraso",
          COALESCE(
            array_agg(DISTINCT n.disciplina) FILTER (
              WHERE GREATEST(COALESCE(n.mac,0), COALESCE(n.nf,0)) > 0
                AND GREATEST(COALESCE(n.mac,0), COALESCE(n.nf,0)) < 10
            ), ARRAY[]::text[]
          ) AS disciplinas
        FROM public.notas n
        WHERE n."anoLetivo" = $1 AND n.trimestre = 3
        GROUP BY n."alunoId"
        HAVING COUNT(DISTINCT CASE
          WHEN GREATEST(COALESCE(n.mac,0), COALESCE(n.nf,0)) > 0
           AND GREATEST(COALESCE(n.mac,0), COALESCE(n.nf,0)) < 10
          THEN n.disciplina
        END) > 0
      `, [anoLetivo]);
      json(res, 200, rows);
    } catch (e) { json(res, 500, { error: (e as Error).message }); }
  });

