  // GET /api/presencas/analise-faltas?alunoId=&turmaId=&disciplina=&mes=&ano=
  // Analisa o padrão de faltas: consecutivas vs interpoladas
  app.get("/api/presencas/analise-faltas", requireAuth, async (req: Request, res: Response) => {
    try {
      const { alunoId, turmaId, disciplina, mes, ano } = req.query as Record<string, string>;
      if (!alunoId || !turmaId || !disciplina) {
        return json(res, 400, { error: "alunoId, turmaId e disciplina são obrigatórios" });
      }
      const params: unknown[] = [alunoId, turmaId, disciplina];
      let sql = `SELECT data, status FROM public.presencas WHERE "alunoId"=$1 AND "turmaId"=$2 AND disciplina=$3 AND status='F'`;
      if (mes && ano) {
        params.push(parseInt(mes)); sql += ` AND EXTRACT(MONTH FROM data::date)=$${params.length}`;
        params.push(parseInt(ano));  sql += ` AND EXTRACT(YEAR FROM data::date)=$${params.length}`;
      } else if (ano) {
        params.push(parseInt(ano));  sql += ` AND EXTRACT(YEAR FROM data::date)=$${params.length}`;
      }
      sql += ' ORDER BY data ASC';
      const rows = await query<{ data: string; status: string }>(sql, params);

    const datas: string[] = rows.map(r => r.data).filter(Boolean);

      // Agrupar em sequências: gap < 7 dias = consecutivas, >= 7 dias = novo grupo
      const sequencias: string[][] = [];
      let current: string[] = [];
      for (const d of datas) {
        if (current.length === 0) {
          current.push(d);
        } else {
          const last = current[current.length - 1];
          const gapMs = new Date(d).getTime() - new Date(last).getTime();
          const gapDias = gapMs / (1000 * 60 * 60 * 24);
          if (gapDias < 7) {
            current.push(d);
          } else {
            sequencias.push([...current]);
            current = [d];
          }
        }
      }
      if (current.length > 0) sequencias.push(current);

      const maxConsecutivas = sequencias.reduce((m, s) => Math.max(m, s.length), 0);
      const seqsConsecutivas = sequencias.filter(s => s.length >= 2);
      const seqsInterpoladas = sequencias.filter(s => s.length === 1);

      let padraoDetectado: string;
      if (datas.length === 0) {
        padraoDetectado = 'sem_faltas';
      } else if (seqsConsecutivas.length > 0 && seqsInterpoladas.length === 0) {
        padraoDetectado = 'consecutiva';
      } else if (seqsConsecutivas.length === 0) {
        padraoDetectado = 'interpolada';
      } else {
        padraoDetectado = 'misto';
      }

      const fmt = (d: string) => {
        try { return new Date(d).toLocaleDateString('pt-AO', { day: '2-digit', month: 'short' }); }
        catch { return d; }
      };

      const resumo = datas.length === 0
        ? 'Sem faltas registadas nas presenças.'
        : padraoDetectado === 'consecutiva'
          ? `${datas.length} falta(s) consecutiva(s) — maior sequência: ${maxConsecutivas} aula(s) seguidas.`
          : padraoDetectado === 'interpolada'
            ? `${datas.length} falta(s) interpolada(s) — distribuídas com intervalos ≥ 7 dias.`
            : `${datas.length} falta(s): ${seqsConsecutivas.length} sequência(s) consecutiva(s) + ${seqsInterpoladas.length} falta(s) isolada(s).`;

      // Art. 23º §7/§15 — Calcular limite de faltas injustificadas por trimestre (Decreto 04/2026)
      // Regra: 1 tempo/sem → 3 faltas; 2 tempos/sem → 4 faltas; >2 tempos/sem → 5 faltas
      let cargaHoraria = 0;
      let faltasRetencaoPorTempos = false;
      let limiteInjustificadasTrimestre = 0;
      try {
        const cfgRows = await query<{ faltasRetencaoPorTempos: boolean }>(`SELECT "faltasRetencaoPorTempos" FROM public.config_geral LIMIT 1`, []);
        faltasRetencaoPorTempos = cfgRows[0]?.faltasRetencaoPorTempos ?? false;
        if (faltasRetencaoPorTempos) {
          // Tentar obter cargaHoraria da disciplina na turma
          const discRows = await query<{ cargaHoraria: number }>(`
            SELECT COALESCE(cd."cargaHoraria", 2) AS "cargaHoraria"
            FROM public.turmas t
            JOIN public.curso_disciplinas cd ON cd."cursoId" = t."cursoId" AND cd.removida = false
            JOIN public.disciplinas d ON d.id = cd."disciplinaId"
            WHERE t.id = $1 AND (LOWER(d.nome) = LOWER($2) OR LOWER(d.codigo) = LOWER($2))
            LIMIT 1
          `, [turmaId, disciplina]);
          cargaHoraria = discRows[0]?.cargaHoraria ?? 2;
          // Tabela Art. 23º §7: 1→3, 2→4, >2→5 faltas injustificadas/trimestre
          limiteInjustificadasTrimestre = cargaHoraria <= 1 ? 3 : cargaHoraria === 2 ? 4 : 5;
        }
      } catch { /* ignorar erro — funcionalidade adicional */ }

      json(res, 200, {
        totalFaltas: datas.length,
        padraoDetectado,
        maxConsecutivas,
        sequencias: sequencias.map(s => ({
          datas: s,
          datasFormatadas: s.map(fmt),
          quantidade: s.length,
          tipo: s.length >= 2 ? 'consecutiva' : 'interpolada',
        })),
        resumo,
        // Art. 23º §7/§15 — limites por tempos lectivos
        faltasRetencaoPorTempos,
        cargaHoraria,
        limiteInjustificadasTrimestre,
      });
    } catch (e) { json(res, 500, { error: (e as Error).message }); }
  });

  // GET /api/presencas/aluno/:alunoId/faltas-por-disciplina
  // Devolve faltas injustificadas por disciplina/turmaId/trimestre (usado no Termo de Frequência)
  // Regulamento Angola (Lei 17/16): trimestre 1=Fev-Abr, 2=Mai-Ago, 3=Set-Nov
  app.get("/api/presencas/aluno/:alunoId/faltas-por-disciplina", requireAuth, async (req: Request, res: Response) => {
    try {
      const { alunoId } = req.params;
      if (!alunoId) return json(res, 400, { error: "alunoId obrigatório" });

      // Estratégia 1: usar registos_falta_mensal (já agrupado por trimestre)
      let rows = await query<{ disciplina: string; turmaId: string; trimestre: number; faltasInj: number; faltasJust: number; totalFaltas: number }>(`
        SELECT
          disciplina,
          "turmaId",
          trimestre,
          SUM("faltasInjustificadas")::int AS "faltasInj",
          SUM("faltasJustificadas")::int   AS "faltasJust",
          SUM("totalFaltas")::int          AS "totalFaltas"
        FROM public.registos_falta_mensal
        WHERE "alunoId" = $1
        GROUP BY disciplina, "turmaId", trimestre
        ORDER BY trimestre
      `, [alunoId]);

      // Estratégia 2 (fallback): contar directamente das presenças
      if (!rows || rows.length === 0) {
        rows = await query<{ disciplina: string; turmaId: string; trimestre: number; faltasInj: number; faltasJust: number; totalFaltas: number }>(`
          SELECT
            disciplina,
            "turmaId",
            CASE
              WHEN EXTRACT(MONTH FROM data::date) IN (2,3,4)   THEN 1
              WHEN EXTRACT(MONTH FROM data::date) IN (5,6,7,8)  THEN 2
              WHEN EXTRACT(MONTH FROM data::date) IN (9,10,11)  THEN 3
              ELSE 1
            END AS trimestre,
            COUNT(CASE WHEN status = 'F' THEN 1 END)::int AS "faltasInj",
            COUNT(CASE WHEN status = 'J' THEN 1 END)::int AS "faltasJust",
            COUNT(CASE WHEN status IN ('F','J') THEN 1 END)::int AS "totalFaltas"
          FROM public.presencas
          WHERE "alunoId" = $1
          GROUP BY disciplina, "turmaId", trimestre
          ORDER BY trimestre
        `, [alunoId]);
      }

      json(res, 200, rows);
    } catch (e) { json(res, 500, { error: (e as Error).message }); }
  });

