          `A matrícula de ${alunoNome}${turmaNome ? ` (${turmaNome})` : ''} foi anulada. Motivo: ${motivoStr}${descricao ? ` — ${descricao}` : ''}.`,
          { tipo: 'anulacao_matricula', link: '/(main)/admin' }
