  // ── CEO: Reset completo da base de dados ─────────────────────────────────
  app.post('/api/ceo/db-reset', requireAuth, async (req: Request, res: Response) => {
    if (req.jwtUser?.role !== 'ceo') {
      return json(res, 403, { error: 'Apenas o CEO pode executar esta operação.' });
    }
    const { confirmacao } = req.body as { confirmacao?: string };
    if (confirmacao !== 'RESETAR') {
      return json(res, 400, { error: 'Confirmação inválida. Escreva exactamente "RESETAR".' });
    }
    try {
      // Tabelas operacionais a limpar (mantém configurações do sistema)
      const tabelasReset = [
        'notificacoes', 'presencas_biblioteca', 'orcamentos_rubrica',
        'recibo_emissoes', 'contas_pagar', 'folhas_salarios',
        'correspondencias', 'mensagens', 'quadro_honra',
        'avaliacoes_parciais', 'pautas', 'notas',
        'justificacoes_falta', 'reconfirmacoes_matricula', 'anotacoes_matricula',
        'solicitacoes_documentos', 'documentos_emitidos', 'materiais',
        'planificacoes', 'sumarios', 'ocorrencias',
        'presencas', 'horarios', 'rupes', 'pagamentos',
        'registros', 'curso_disciplinas', 'turmas', 'salas',
        'funcionarios', 'alunos',
      ];
      const resultados: Record<string, number> = {};
      for (const tabela of tabelasReset) {
        try {
          const r = await query<{count: string}>(`DELETE FROM public.${tabela} RETURNING id`, []);
          resultados[tabela] = r.length;
        } catch {
          resultados[tabela] = -1;
        }
      }
      const total = Object.values(resultados).filter(v => v >= 0).reduce((a, b) => a + b, 0);
      console.log(`[CEO RESET] Base de dados resetada por ${req.jwtUser.email}. ${total} registos removidos.`);
      json(res, 200, {
        ok: true,
        mensagem: `Base de dados resetada com sucesso. ${total} registos removidos.`,
        detalhes: resultados,
      });
    } catch (e) {
      json(res, 500, { error: (e as Error).message });
    }
  });

  app.get('/api/admin/export-csv', requireAuth, requirePermission('admin'), async (req: Request, res: Response) => {
    try {
      const table = (req.query.tabela as string) || 'alunos';
      const allowed = ['alunos', 'funcionarios', 'utilizadores', 'notas', 'presencas', 'pagamentos', 'turmas'];
      if (!allowed.includes(table)) return json(res, 400, { error: 'Tabela não permitida.' });
      const result = await query(`SELECT * FROM public.${table} LIMIT 50000`, []);
      if (result.length === 0) {
        res.setHeader('Content-Type', 'text/csv; charset=utf-8');
        res.setHeader('Content-Disposition', `attachment; filename="${table}.csv"`);
        return res.status(200).send('sem dados\n');
      }
      const headers = Object.keys(result[0]);
      const escape = (v: unknown) => {
        if (v === null || v === undefined) return '';
        const s = String(v).replace(/"/g, '""');
        return /[",\n\r]/.test(s) ? `"${s}"` : s;
      };
      const csvLines = [
        headers.join(','),
        ...result.map(row => headers.map(h => escape(row[h])).join(',')),
      ];
      const filename = `sige-${table}-${new Date().toISOString().slice(0, 10)}.csv`;
      res.setHeader('Content-Type', 'text/csv; charset=utf-8');
      res.setHeader('Content-Disposition', `attachment; filename="${filename}"`);
      res.status(200).send('\uFEFF' + csvLines.join('\r\n'));
    } catch (e) {
      json(res, 500, { error: (e as Error).message });
    }
  });

  // ── Solicitações de Documentos (aluno) ─────────────────────────────────────
  app.get('/api/solicitacoes-documentos', requireAuth, async (req: Request, res: Response) => {
    try {
      const { alunoId, status } = req.query as { alunoId?: string; status?: string };
      let whereClause = '';
      const params: any[] = [];
      const conditions: string[] = [];
      if (alunoId) { params.push(alunoId); conditions.push(`sd."alunoId"=$${params.length}`); }
      if (status) {
        const statuses = String(status).split(',').map(s => s.trim()).filter(Boolean);
        if (statuses.length === 1) {
          params.push(statuses[0]);
          conditions.push(`sd.status=$${params.length}`);
        } else if (statuses.length > 1) {
          const placeholders = statuses.map((s, i) => { params.push(s); return `$${params.length}`; }).join(',');
          conditions.push(`sd.status IN (${placeholders})`);
        }
      }
      if (conditions.length) whereClause = 'WHERE ' + conditions.join(' AND ');
      const rows = await query<JsonObject>(`
        SELECT sd.*,
          a.nome AS "nomeAluno",
          a.apelido AS "apelidoAluno",
          a."numeroMatricula" AS "alunoNumMatricula",
          a."turmaId" AS "alunoTurmaId",
          t.nome AS "nomeTurma",
          t.classe AS "classeAluno"
        FROM public.solicitacoes_documentos sd
        LEFT JOIN public.alunos a ON a.id = sd."alunoId"
        LEFT JOIN public.turmas t ON t.id = a."turmaId"
        ${whereClause}
        ORDER BY sd."createdAt" DESC
      `, params);
      json(res, 200, rows);
    } catch (e) {
      json(res, 500, { error: (e as Error).message });
    }
  });

  app.post('/api/solicitacoes-documentos', requireAuth, async (req: Request, res: Response) => {
    try {
      const b = requireBodyObject(req) as any;
      // Block duplicate active request for same student + document type
      const existing = await query<JsonObject>(
        `SELECT id FROM public.solicitacoes_documentos
         WHERE "alunoId"=$1 AND tipo=$2 AND status NOT IN ('concluido','cancelado')
         LIMIT 1`,
        [b.alunoId, b.tipo]
      );
      if (existing.length > 0) {
        return json(res, 409, { error: 'duplicate', message: `Já existe uma solicitação activa de "${b.tipo}" para este aluno. Aguarde a conclusão ou cancele a anterior.` });
      }
      const rows = await query<JsonObject>(
        `INSERT INTO public.solicitacoes_documentos
          (id,"alunoId",tipo,motivo,observacao,status,"createdAt","updatedAt")
         VALUES ($1,$2,$3,$4,$5,$6,NOW(),NOW()) RETURNING *`,
        [b.id, b.alunoId, b.tipo, b.motivo ?? '', b.observacao ?? '', b.status ?? 'pendente']
      );
      const sol = rows[0];
      // Notify finance users for payment validation (new step before secretaria)
      try {
        const alunoRows = await query<JsonObject>(`SELECT nome, apelido FROM public.alunos WHERE id=$1`, [b.alunoId]);
        const nomeAluno = alunoRows[0] ? `${alunoRows[0].nome} ${alunoRows[0].apelido}` : 'Aluno';
        const msgDoc = `${nomeAluno} solicitou: ${b.tipo}. Confirme o pagamento antes de encaminhar à secretaria.`;
        const financeRows = await query<{ id: string; email: string; nome: string }>(
          `SELECT id, email, nome FROM public.utilizadores WHERE role IN ('financeiro','admin','director','ceo','pca') AND ativo=true`,
          []
        );
        const hoje = new Date().toISOString().slice(0, 10);
        const marca = await obterMarcaEmpresa();
        for (const fin of financeRows) {
          await query(
            `INSERT INTO public.notificacoes ("utilizadorId","titulo","mensagem","tipo","data","lida","link")
             VALUES ($1,$2,$3,$4,$5,false,$6)`,
            [fin.id, 'Nova Solicitação — Validação Financeira', msgDoc, 'solicitacao_documento', hoje, '/(main)/financeiro']
          );
          if (fin.email && process.env.RESEND_API_KEY) {
            try {
              const { sendGuardianNotificationEmail } = await import('./email');
              await sendGuardianNotificationEmail(fin.email, fin.nome || 'Responsável', 'Nova Solicitação de Documento', msgDoc, 'geral', undefined, marca);
            } catch {}
          }
        }
        // Notificar também a secretaria
        await notificarAdmins(
          'Nova Solicitação de Documento',
          `${nomeAluno} solicitou: ${b.tipo}. Aguarda validação financeira e processamento.`,
          { tipo: 'solicitacao_documento', link: '/(main)/documentos', roles: ['chefe_secretaria','secretaria'] }
        );
      } catch (notifErr) {
        console.error('[solicitacoes] Falha ao criar notificação:', notifErr);
      }
      json(res, 201, sol);
    } catch (e) {
      json(res, 400, { error: (e as Error).message });
    }
  });

  app.put('/api/solicitacoes-documentos/:id', requireAuth, async (req: Request, res: Response) => {
    try {
      const { id } = req.params;
      const b = requireBodyObject(req) as any;
      const allowed = ['status', 'resposta', 'referenciaPagamento', 'validadoPorFinanceiro', 'validadoPorFinanceiroId', 'validadoPorFinanceiroNome', 'validadoPorFinanceiroEm', 'motivoRejeicaoFinanceiro'];
      const setParts: string[] = [];
      const values: any[] = [];
      for (const key of allowed) {
        if (b[key] !== undefined) {
          values.push(b[key]);
          setParts.push(`"${key}"=$${values.length}`);
        }
      }
      if (!setParts.length) return json(res, 400, { error: 'Nada para atualizar.' });
      values.push(new Date().toISOString());
      setParts.push(`"updatedAt"=$${values.length}`);
      values.push(id);
      const rows = await query<JsonObject>(
        `UPDATE public.solicitacoes_documentos SET ${setParts.join(',')} WHERE id=$${values.length} RETURNING *`,
        values
      );
      const updated = rows[0];
      // Notificação automática ao aluno quando o documento fica pronto
      if (b.status === 'pronto' && updated) {
        try {
          const alunoId = (updated as any).alunoId;
          const tipoDoc = (updated as any).tipo || 'documento';
          if (alunoId) {
            notifyAlunoDocumentoPronte(alunoId, tipoDoc).catch(() => {});
          }
        } catch (notifErr) {
          console.warn('[notify] Falha ao notificar aluno sobre documento:', (notifErr as Error).message);
        }
      }

      // Notificação ao aluno quando o documento é aprovado (antes de ficar pronto)
      if (b.status === 'aprovado' && updated) {
        try {
          const alunoId = (updated as any).alunoId;
          const tipoDoc = (updated as any).tipo || 'documento';
          if (alunoId) {
            notifyAluno(
              alunoId,
              '✅ Pedido aprovado',
              `O teu pedido de ${tipoDoc} foi aprovado. Em breve estará pronto para levantamento.`,
              'sucesso',
              '/(main)/portal-estudante'
            ).catch(() => {});
          }
        } catch (notifErr) {
          console.warn('[notify] Falha ao notificar aluno sobre aprovação de documento:', (notifErr as Error).message);
        }
      }

      // Notificação ao aluno quando o documento é rejeitado
      if (b.status === 'rejeitado' && updated) {
        try {
          const alunoId = (updated as any).alunoId;
          const tipoDoc = (updated as any).tipo || 'documento';
          const resposta = b.resposta || '';
          if (alunoId) {
            notifyAluno(
              alunoId,
              '❌ Pedido não aprovado',
              `O teu pedido de ${tipoDoc} não foi aprovado.${resposta ? ' Motivo: ' + resposta : ' Contacta a secretaria para mais informações.'}`,
              'aviso',
              '/(main)/portal-estudante'
            ).catch(() => {});
          }
        } catch (notifErr) {
          console.warn('[notify] Falha ao notificar aluno sobre rejeição de documento:', (notifErr as Error).message);
        }
      }

      // When finance validates, notify secretaria users
      if (b.status === 'validado_financeiro' && updated) {
        try {
          const alunoRows = await query<JsonObject>(`SELECT nome, apelido FROM public.alunos WHERE id=$1`, [(updated as any).alunoId]);
          const nomeAluno = alunoRows[0] ? `${alunoRows[0].nome} ${alunoRows[0].apelido}` : 'Aluno';
          const secRows = await query<JsonObject>(
            `SELECT id FROM public.utilizadores WHERE role IN ('chefe_secretaria','secretaria','admin','director','ceo','pca') AND ativo=true`,
            []
          );
          const hoje = new Date().toISOString().slice(0, 10);
          for (const sec of secRows) {
            await query(
              `INSERT INTO public.notificacoes ("utilizadorId","titulo","mensagem","tipo","data","lida","link")
               VALUES ($1,$2,$3,$4,$5,false,$6)`,
              [
                sec.id,
                'Solicitação Validada pelo Financeiro',
                `Pagamento confirmado para: ${(updated as any).tipo} — ${nomeAluno}. Pronto para emissão.`,
                'solicitacao_documento',
                hoje,
                '/(main)/solicitacoes-secretaria',
              ]
            );
          }
        } catch (notifErr) {
          console.error('[solicitacoes] Falha ao notificar secretaria:', notifErr);
        }
      }
      json(res, 200, updated);
    } catch (e) {
      json(res, 500, { error: (e as Error).message });
    }
  });

  // ── Comprovativo de Matrícula / Reconfirmação — dados para PDF ──────────────
  // Aceita ?alunoId=xxx (dados completos + deficiências) ou ?classe=X&cursoNome=Y (só disciplinas)
  app.get('/api/comprovativo-matricula', requireAuth, async (req: Request, res: Response) => {
    try {
      const { alunoId, classe, cursoNome } = req.query as Record<string, string | undefined>;

      // Config geral (sempre necessária)
      const configRows = await query<JsonObject>(
        `SELECT "nomeEscola","directorGeral","provincia","municipio","telefoneEscola","emailEscola","notaMinimaAprovacao"
         FROM public.config_geral LIMIT 1`, []
      );
      const config = (configRows[0] || {}) as any;
      const notaMin = Number(config.notaMinimaAprovacao ?? 10);

      let aluno: any = null;
      let disciplinas: Array<{ nome: string; cargaHoraria?: number }> = [];
      let disciplinasComDeficiencia: Array<{ nome: string; mfd: number; anoLetivo: string }> = [];

      if (alunoId) {
        // ── Modo completo: aluno já matriculado ────────────────────────────────
        const alunoRows = await query<JsonObject>(
          `SELECT a.*, t.nome AS "turmaNome", t.classe, t.nivel, t.turno, t."anoLetivo",
                  t."cursoId", c.nome AS "cursoNome", c."areaFormacao" AS "cursoArea"
           FROM public.alunos a
           LEFT JOIN public.turmas t ON t.id = a."turmaId"
           LEFT JOIN public.cursos c ON c.id = t."cursoId"
           WHERE a.id = $1`, [alunoId]
        );
        if (!alunoRows[0]) return json(res, 404, { error: 'Aluno não encontrado' });
        aluno = alunoRows[0];

        // Disciplinas do plano curricular
        if (aluno.cursoId) {
          const rows = await query<JsonObject>(
            `SELECT d.nome, cd."cargaHoraria"
             FROM public.disciplinas d
             JOIN public.curso_disciplinas cd ON cd."disciplinaId" = d.id AND cd.removida = false
             WHERE cd."cursoId" = $1 AND d.ativo = true
             ORDER BY cd.ordem ASC NULLS LAST, d.nome ASC`, [aluno.cursoId]
          );
          disciplinas = rows.map((r: any) => ({ nome: r.nome, cargaHoraria: r.cargaHoraria }));
        } else if (aluno.turmaId) {
          const rows = await query<JsonObject>(
            `SELECT d.nome, d."cargaHoraria"
             FROM public.disciplinas d
             JOIN public.turma_disciplinas td ON td."disciplinaId" = d.id
             WHERE td."turmaId" = $1 AND d.ativo = true
             ORDER BY td.ordem ASC NULLS LAST, d.nome ASC`, [aluno.turmaId]
          );
          disciplinas = rows.map((r: any) => ({ nome: r.nome, cargaHoraria: r.cargaHoraria }));
        }

        // Disciplinas com deficiência — MFD >= 7 e < notaMin no ano lectivo mais recente
        const notasRows = await query<JsonObject>(
          `SELECT disciplina, "anoLetivo",
                  ROUND(AVG(CASE WHEN nf > 0 THEN nf WHEN mt1 > 0 THEN mt1 ELSE NULL END)::numeric, 1) AS mfd
           FROM public.notas
           WHERE "alunoId" = $1
             AND (nf > 0 OR mt1 > 0)
           GROUP BY disciplina, "anoLetivo"
           HAVING AVG(CASE WHEN nf > 0 THEN nf WHEN mt1 > 0 THEN mt1 ELSE NULL END) >= 7
              AND AVG(CASE WHEN nf > 0 THEN nf WHEN mt1 > 0 THEN mt1 ELSE NULL END) < $2
           ORDER BY "anoLetivo" DESC, disciplina ASC`, [alunoId, notaMin]
        );
        // Apenas o ano lectivo mais recente com deficiências
        const anosComDef = [...new Set((notasRows as any[]).map(r => r.anoLetivo))].sort().reverse();
        const anoRef = anosComDef[0] || null;
        disciplinasComDeficiencia = anoRef
          ? (notasRows as any[])
              .filter(r => r.anoLetivo === anoRef)
              .map(r => ({ nome: r.disciplina, mfd: Number(r.mfd), anoLetivo: r.anoLetivo }))
          : [];

      } else if (classe) {
        // ── Modo leve: apenas disciplinas por classe/curso ─────────────────────
        if (cursoNome) {
          // II Ciclo: via curso com esse nome
          const cursoRows = await query<JsonObject>(
            `SELECT id FROM public.cursos WHERE nome ILIKE $1 AND ativo = true LIMIT 1`, [cursoNome]
          );
          const cursoId = (cursoRows[0] as any)?.id;
          if (cursoId) {
            const rows = await query<JsonObject>(
              `SELECT d.nome, cd."cargaHoraria"
               FROM public.disciplinas d
               JOIN public.curso_disciplinas cd ON cd."disciplinaId" = d.id AND cd.removida = false
               WHERE cd."cursoId" = $1 AND d.ativo = true
               ORDER BY cd.ordem ASC NULLS LAST, d.nome ASC`, [cursoId]
            );
            disciplinas = rows.map((r: any) => ({ nome: r.nome, cargaHoraria: r.cargaHoraria }));
          }
        }
        // Fallback ou turmas sem curso: via turma_disciplinas da 1ª turma com essa classe
        if (disciplinas.length === 0) {
          const turmaRows = await query<JsonObject>(
            `SELECT t.id FROM public.turmas t
             WHERE t.ativo = true AND t.classe = $1 AND t."cursoId" IS NULL LIMIT 1`, [classe]
          );
          const turmaId = (turmaRows[0] as any)?.id;
          if (turmaId) {
            const rows = await query<JsonObject>(
              `SELECT d.nome, d."cargaHoraria"
               FROM public.disciplinas d
               JOIN public.turma_disciplinas td ON td."disciplinaId" = d.id
               WHERE td."turmaId" = $1 AND d.ativo = true
               ORDER BY td.ordem ASC NULLS LAST, d.nome ASC`, [turmaId]
            );
            disciplinas = rows.map((r: any) => ({ nome: r.nome, cargaHoraria: r.cargaHoraria }));
          }
        }
      }

      json(res, 200, { aluno, config, disciplinas, disciplinasComDeficiencia });
    } catch (e) {
      json(res, 500, { error: (e as Error).message });
    }
  });

