  async function obterProximoNumeroFecho(anoLetivo: string): Promise<number> {
    const chave = anoLetivo || 'geral';
    await query(
      `INSERT INTO public.fecho_caixa_sequencias ("anoLetivo","ultimoNumero") VALUES ($1,0) ON CONFLICT ("anoLetivo") DO NOTHING`,
      [chave]
    );
    const rows = await query<{ n: number }>(
      `UPDATE public.fecho_caixa_sequencias SET "ultimoNumero" = "ultimoNumero" + 1 WHERE "anoLetivo"=$1 RETURNING "ultimoNumero" AS n`,
      [chave]
    );
    return rows[0]?.n ?? 1;
  }

  async function agregarFechoCaixa(data: string) {
    const pagamentos = await query<JsonObject>(
      `SELECT
         COALESCE(SUM(CASE WHEN "metodoPagamento"='dinheiro' THEN valor ELSE 0 END),0) AS caixa,
         COALESCE(SUM(CASE WHEN "metodoPagamento"='transferencia' THEN valor ELSE 0 END),0) AS transferencia,
         COALESCE(SUM(CASE WHEN "metodoPagamento"='multicaixa' THEN valor ELSE 0 END),0) AS multicaixa,
         COALESCE(SUM(valor),0) AS total,
         COUNT(*) AS num
       FROM public.pagamentos
       WHERE status='pago' AND data=$1`,
      [data]
    );
    const porRubrica = await query<JsonObject>(
      `SELECT t.nome AS rubrica, t.tipo, SUM(p.valor) AS total, COUNT(p.id) AS qtd
       FROM public.pagamentos p
       LEFT JOIN public.taxas t ON t.id = p."taxaId"
       WHERE p.status='pago' AND p.data=$1
       GROUP BY t.nome, t.tipo ORDER BY total DESC`,
      [data]
    );
    return { pg: pagamentos[0] as any, porRubrica };
  }

