  // POST /api/comunicados/marcar-visualizacao — chamado pelo FlashScreenOverlay
  app.post('/api/comunicados/marcar-visualizacao', requireAuth, async (req, res) => {
    try {
      const b = requireBodyObject(req);
      const titulo = String(b.titulo || '').trim();
      const dataInicio = String(b.dataInicio || '').trim();
      const userId = req.jwtUser?.id;
      const userRole = req.jwtUser?.role || '';
      if (!titulo || !userId) return json(res, 400, { error: 'titulo e utilizador obrigatórios.' });

      // encontrar comunicado pelo título + dataInicio
      const comRows = await query<any>(
        `SELECT id FROM public.comunicados WHERE titulo=$1 AND (data_inicio=$2 OR ($2='' AND data_inicio IS NULL)) LIMIT 1`,
        [titulo, dataInicio]
      ).catch(() => []);
      // fallback: só pelo título
      const comRows2 = comRows.length ? comRows : await query<any>(
        `SELECT id FROM public.comunicados WHERE titulo=$1 ORDER BY criado_em DESC LIMIT 1`, [titulo]
      ).catch(() => []);
      if (!comRows2.length) return json(res, 404, { error: 'Comunicado não encontrado.' });
      const comunicadoId = comRows2[0].id;

      // obter nome e aluno associado
      const uRows = await query<any>(
        `SELECT "nomeCompleto", email FROM public.utilizadores WHERE id=$1 LIMIT 1`, [userId]
      ).catch(() => []);
      const nome = uRows[0]?.nomeCompleto || 'Utilizador';

      let alunoId: string | null = null;
      let alunoNome: string | null = null;
      if (userRole === 'encarregado') {
        const aRows = await query<any>(
          `SELECT id, "nomeCompleto" FROM public.alunos
           WHERE "encarregadoEmail"=$1 OR "utilizadorId"=(
             SELECT id FROM public.utilizadores WHERE id=$1 LIMIT 1
           ) LIMIT 1`,
          [uRows[0]?.email || '']
        ).catch(() => []);
        if (aRows[0]) { alunoId = aRows[0].id; alunoNome = aRows[0].nomeCompleto; }
      }

      // INSERT OR IGNORE (unique constraint)
      await query(
        `INSERT INTO public.comunicados_visualizacoes
           (comunicado_id, utilizador_id, nome, role, aluno_id, aluno_nome)
         VALUES ($1,$2,$3,$4,$5,$6)
         ON CONFLICT (comunicado_id, utilizador_id) DO NOTHING`,
        [comunicadoId, userId, nome, userRole, alunoId, alunoNome]
      ).catch(() => {});

      json(res, 200, { ok: true });
    } catch (e) { json(res, 500, { error: (e as Error).message }); }
  });

