  app.put('/api/comunicados/:id', requireAuth, async (req, res) => {
    try {
      const { id } = req.params;
      const b = requireBodyObject(req);
      const titulo = String(b.titulo || '').trim();
      if (!titulo) return json(res, 400, { error: 'Título é obrigatório.' });
      const rows = await query<JsonObject>(
        `UPDATE public.comunicados
            SET titulo=$1, mensagem=$2, destinatarios=$3, imagem_url=$4,
                duracao=$5, bg_color=$6, data_inicio=$7, data_fim=$8, ativa=$9
          WHERE id=$10
         RETURNING id, titulo, mensagem, destinatarios, imagem_url AS "imagemUrl",
                   duracao, bg_color AS "bgColor", data_inicio AS "dataInicio",
                   data_fim AS "dataFim", ativa, criado_em AS "criadoEm"`,
        [
          titulo,
          String(b.mensagem || '').trim(),
          String(b.destinatarios || 'todos'),
          String(b.imagemUrl || '').trim(),
          Number(b.duracao) > 0 ? Number(b.duracao) : 5,
          String(b.bgColor || '#0A1628').trim(),
          String(b.dataInicio || '').trim(),
          String(b.dataFim || '').trim(),
          Boolean(b.ativa),
          id,
        ]
      );
      if (!rows[0]) return json(res, 404, { error: 'Comunicado não encontrado.' });
      json(res, 200, rows[0]);
    } catch (e) { json(res, 500, { error: (e as Error).message }); }
  });

