  // ── Alertas automáticos de expiração de licença ────────────────────────────
  async function verificarEEnviarAvisosExpiracao() {
    try {
      const c = await query<any>(
        `SELECT "licencaExpiracao","licencaGracePeriodDias","licencaUltimoAvisoEmail" FROM public.config_geral LIMIT 1`, []
      );
      const cfg = c[0];
      if (!cfg?.licencaExpiracao) return;
      const hoje = new Date(); hoje.setHours(0, 0, 0, 0);
      const exp = new Date(cfg.licencaExpiracao + 'T00:00:00');
      const diff = Math.floor((exp.getTime() - hoje.getTime()) / 86400000);
      // Só envia para 15 ou 7 dias restantes
      if (diff !== 15 && diff !== 7) return;
      const ultimoAviso = cfg.licencaUltimoAvisoEmail ? cfg.licencaUltimoAvisoEmail.slice(0, 10) : null;
      const hojeStr = hoje.toISOString().slice(0, 10);
      if (ultimoAviso === hojeStr) return; // já enviou hoje
      // Busca dados de pagamento
      const cfgPag = await query<any>(`SELECT "licencaIban","licencaBic","licencaMulticaixaRef" FROM public.config_geral LIMIT 1`, []);
      const cp = cfgPag[0] || {};
      const linhasPag: string[] = [];
      if (cp.licencaIban) linhasPag.push(`IBAN (BAI): ${cp.licencaIban}`);
      if (cp.licencaBic) linhasPag.push(`BIC: ${cp.licencaBic}`);
      if (cp.licencaMulticaixaRef) linhasPag.push(`Multicaixa Express: ${cp.licencaMulticaixaRef}`);
      const dadosPag = linhasPag.length ? `\n\nDados para pagamento:\n${linhasPag.join('\n')}` : '';
      const titulo = `⚠️ Licença expira em ${diff} dias`;
      const msg = `A subscrição SIGA expira em ${diff} dia${diff === 1 ? '' : 's'} (${cfg.licencaExpiracao}). Renove atempadamente para evitar interrupções.${dadosPag}`;
      await notificarCeo(titulo, msg);
      await query(`UPDATE public.config_geral SET "licencaUltimoAvisoEmail"=$1`, [hojeStr]);
      console.log(`[licenca-aviso] Email enviado — ${diff} dias restantes.`);
    } catch (err) {
      console.warn('[licenca-aviso]', (err as Error).message);
    }
  }

