  // Escalões de desconto por volume (jsonb) — editáveis pelo CEO
  try {
    await query(`ALTER TABLE public.config_geral ADD COLUMN IF NOT EXISTS "licencaDescontosVolume" jsonb`, []);
    // Inicializa com defaults se ainda estiver vazio
    await query(`UPDATE public.config_geral
                 SET "licencaDescontosVolume" = $1::jsonb
                 WHERE "licencaDescontosVolume" IS NULL`,
      [JSON.stringify([
        { min: 0,    max: 100,  perc: 0,  label: '1-100' },
        { min: 101,  max: 500,  perc: 5,  label: '101-500' },
        { min: 501,  max: 1000, perc: 7,  label: '501-1000' },
        { min: 1001, max: 3000, perc: 10, label: '1001-3000' },
        { min: 3001, max: 5000, perc: 10, label: '3001-5000' },
        { min: 5001, max: null, perc: 10, label: '5001+' },
      ])]
    );
    // Migração: actualiza escalão 3001-5000 de 15% (default antigo) para 10% se ainda
    // tiver o valor antigo. Não toca em escalões que o CEO já personalizou para outros %.
    try {
      await query(
        `UPDATE public.config_geral
            SET "licencaDescontosVolume" = (
              SELECT jsonb_agg(
                CASE
                  WHEN (e->>'min')::int = 3001 AND (e->>'max')::int = 5000 AND (e->>'perc')::int = 15
                  THEN jsonb_set(e, '{perc}', to_jsonb(10))
                  ELSE e
                END
              )
              FROM jsonb_array_elements("licencaDescontosVolume") e
            )
          WHERE "licencaDescontosVolume" IS NOT NULL`,
        []
      );
      console.log('[migration] escalão 3001-5000 actualizado de 15% para 10% (onde aplicável).');
    } catch (err) { console.warn('[migration] update 3001-5000:', (err as Error).message); }
    // Migração: garante que nenhum escalão tem desconto acima de 10% (cap máximo)
    // Corrige o escalão 5001+ que tinha 20% no default antigo, e actualiza label '5000+' → '5001+'
    try {
      await query(
        `UPDATE public.config_geral
            SET "licencaDescontosVolume" = (
              SELECT jsonb_agg(
                CASE
                  WHEN (e->>'perc')::numeric > 10
                  THEN jsonb_set(e, '{perc}', to_jsonb(10))
                  WHEN e->>'label' = '5000+' AND (e->>'min')::int = 5001
                  THEN jsonb_set(e, '{label}', to_jsonb('5001+'::text))
                  ELSE e
                END
              )
              FROM jsonb_array_elements("licencaDescontosVolume") e
            )
          WHERE "licencaDescontosVolume" IS NOT NULL`,
        []
      );
      console.log('[migration] escalões: desconto máximo de 10% aplicado e label 5001+ corrigido.');
    } catch (err) { console.warn('[migration] cap 10% escalões:', (err as Error).message); }
    console.log('[migration] config_geral.licencaDescontosVolume ensured (com defaults).');
  } catch (err) { console.warn('[migration] licencaDescontosVolume:', (err as Error).message); }

