  app.post('/api/ai-support', requireAuth, async (req: Request, res: Response) => {
    try {
      const jwtUser = (req as any).jwtUser as { userId: string; role: string; email: string } | undefined;
      if (!jwtUser) return res.status(401).json({ error: 'Não autenticado' });

      const { message, history = [], userName = '', stream: streamMode = false, currentScreen = '' } = req.body as {
        message: string; history: Array<{ role: string; content: string }>;
        userName?: string; stream?: boolean; currentScreen?: string;
      };
      if (!message?.trim()) return res.status(400).json({ error: 'Mensagem vazia' });

      const geminiKey = process.env.GEMINI_API_KEY;
      if (!geminiKey) return res.status(503).json({ error: 'Serviço de IA não configurado. Adiciona GEMINI_API_KEY nos Secrets.' });

      const GEMINI_MODEL = 'gemini-2.5-flash';
      const GEMINI_URL = `https://generativelanguage.googleapis.com/v1beta/models/${GEMINI_MODEL}:generateContent?key=${geminiKey}`;
      const GEMINI_STREAM_URL = `https://generativelanguage.googleapis.com/v1beta/models/${GEMINI_MODEL}:streamGenerateContent?alt=sse&key=${geminiKey}`;

      const [realtimeCtx, dynamicCtx] = await Promise.all([
        fetchRealtimeContext(jwtUser.role, jwtUser.userId),
        fetchDynamicContext(jwtUser.role, jwtUser.userId, message.trim()),
      ]);
      let systemPrompt = buildSystemPrompt(jwtUser.role, userName || jwtUser.email, realtimeCtx);
      if (dynamicCtx) systemPrompt += `\n\n${dynamicCtx}`;
      if (currentScreen) systemPrompt += `\n\nECRÃ ACTUAL: O utilizador está no ecrã "${currentScreen}" da aplicação.`;

      // Converter histórico para formato Gemini
      const geminiContents = [
        ...history.slice(-20).map((m: { role: string; content: string }) => ({
          role: m.role === 'assistant' ? 'model' : 'user',
          parts: [{ text: m.content }],
        })),
        { role: 'user', parts: [{ text: message.trim() }] },
      ];
      const geminiBody = {
        system_instruction: { parts: [{ text: systemPrompt }] },
        contents: geminiContents,
        generationConfig: { maxOutputTokens: 800, temperature: 0.3 },
      };
      // ── STREAMING MODE ─────────────────────────────────────────────────────
      if (streamMode) {
        res.setHeader('Content-Type', 'text/event-stream; charset=utf-8');
        res.setHeader('Cache-Control', 'no-cache, no-transform');
        res.setHeader('Connection', 'keep-alive');
        res.setHeader('X-Accel-Buffering', 'no');
        if ((res as any).flushHeaders) (res as any).flushHeaders();

        let fullReply = '';
        let streamOk = false;

        try {
          const r = await fetch(GEMINI_STREAM_URL, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(geminiBody),
          });
          if (r.ok && r.body) {
            streamOk = true;
            const reader = (r.body as any).getReader();
            const decoder = new TextDecoder();
            let buf = '';
            while (true) {
              const { done, value } = await reader.read();
              if (done) break;
              buf += decoder.decode(value, { stream: true });
              const parts = buf.split('\n'); buf = parts.pop() ?? '';
              for (const line of parts) {
                if (!line.startsWith('data: ')) continue;
                const raw = line.slice(6).trim();
                if (!raw || raw === '[DONE]') continue;
                try {
                  const parsed = JSON.parse(raw);
                  const chunk = parsed.candidates?.[0]?.content?.parts?.[0]?.text ?? '';
                  if (chunk) { fullReply += chunk; res.write(`data: ${JSON.stringify({ chunk })}\n\n`); }
                } catch { }
              }
            }
          } else {
            const errBody = await r.text().catch(() => '');
            console.warn(`[ai-support] Gemini stream HTTP ${r.status}: ${errBody.slice(0, 200)}`);
          }
        } catch (e) { console.warn('[ai-support] Gemini stream error:', (e as Error).message); }

        // Fallback não-streaming se stream falhou
        if (!streamOk || !fullReply) {
          try {
            const r2 = await fetch(GEMINI_URL, {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify(geminiBody),
            });
            if (r2.ok) {
              const d = await r2.json() as any;
              const chunk = d?.candidates?.[0]?.content?.parts?.[0]?.text ?? '';
              if (chunk) { fullReply = chunk; res.write(`data: ${JSON.stringify({ chunk })}\n\n`); streamOk = true; }
            }
          } catch (e) { console.warn('[ai-support] Gemini fallback error:', (e as Error).message); }
        }

        if (!streamOk || !fullReply) {
          res.write(`data: ${JSON.stringify({ error: 'Não foi possível contactar o assistente de IA.' })}\n\n`);
          res.end(); return;
        }
        const actions = detectActions(fullReply, jwtUser.role);
        res.write(`data: ${JSON.stringify({ done: true, actions, provider: 'Google Gemini', model: GEMINI_MODEL })}\n\n`);
        res.end(); return;
      }

      // ── NON-STREAMING MODE ─────────────────────────────────────────────────
      let reply = '';
      let success = false;
      try {
        const r = await fetch(GEMINI_URL, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(geminiBody),
        });
        if (r.ok) {
          const d = await r.json() as any;
          reply = d?.candidates?.[0]?.content?.parts?.[0]?.text ?? '';
          success = !!reply;
        } else console.warn('[ai-support] Gemini non-stream failed:', r.status);
      } catch (e) { console.warn('[ai-support] Gemini exception:', (e as Error).message); }

      if (!success) return res.status(502).json({ error: 'Não foi possível contactar o assistente de IA.' });

      const actions = detectActions(reply, jwtUser.role);
      return res.json({ reply, actions, provider: 'Google Gemini', model: GEMINI_MODEL });
    } catch (err) {
      console.error('[ai-support]', err);
      return res.status(500).json({ error: 'Erro interno.' });
    }
  });

  // ── AI DYNAMIC SUGGESTIONS ──────────────────────────────────────────────────
  app.get('/api/ai-dynamic-suggestions', requireAuth, async (req: Request, res: Response) => {
    const jwtUser = (req as any).jwtUser as { userId: string; role: string } | undefined;
    if (!jwtUser) return res.status(401).json({ error: 'Não autenticado' });
    const { role, userId } = jwtUser;
    const anoAtual = new Date().getFullYear().toString();
    const mesAtual = new Date().getMonth() + 1;
    try {
      const sugs: Array<{ text: string; icon: string; urgent?: boolean }> = [];

      if (['ceo', 'pca', 'admin', 'director'].includes(role)) {
        const [aR] = await query<{ total: string }>(`SELECT COUNT(*) as total FROM alunos WHERE ativo = true AND situacao = 'activo'`, []).catch(() => [{ total: '?' }]);
        sugs.push({ text: `Ver resumo dos ${aR?.total ?? '?'} alunos activos`, icon: 'people-outline' });
        const [pR] = await query<{ total: string }>(`SELECT COUNT(*) as total FROM pagamentos WHERE status = 'pendente'`, []).catch(() => [{ total: '0' }]);
        if (Number(pR?.total) > 0) sugs.push({ text: `${pR?.total} pagamentos pendentes`, icon: 'alert-circle-outline', urgent: true });
        sugs.push({ text: `Receita de ${mesAtual}/${anoAtual}`, icon: 'cash-outline' });
      }
      if (role === 'professor') {
        const [u] = await query<{ professorId: string | null }>(`SELECT "professorId" FROM utilizadores WHERE id = $1`, [userId]).catch(() => [{ professorId: null }]);
        if (u?.professorId) {
          const [pp] = await query<{ total: string }>(`SELECT COUNT(*) as total FROM notas n JOIN turmas t ON n."turmaId" = t.id WHERE n.lancado = false AND (t."professorId" = $1 OR t."professoresIds" @> $2::jsonb) AND t."anoLetivo" = $3`, [u.professorId, JSON.stringify([u.professorId]), anoAtual]).catch(() => [{ total: '0' }]);
          if (Number(pp?.total) > 0) sugs.push({ text: `${pp?.total} pautas por lançar`, icon: 'document-text-outline', urgent: true });
          const turmas = await query<{ nome: string }>(`SELECT nome FROM turmas WHERE ativo = true AND "anoLetivo" = $1 AND ("professorId" = $2 OR "professoresIds" @> $3::jsonb) LIMIT 3`, [anoAtual, u.professorId, JSON.stringify([u.professorId])]).catch(() => []);
          if (turmas.length > 0) sugs.push({ text: `As minhas ${turmas.length} turma(s): ${turmas.map(t => t.nome).join(', ')}`, icon: 'school-outline' });
        }
        sugs.push({ text: 'Como registar presenças?', icon: 'calendar-outline' });
      }
      if (role === 'aluno') {
        const [u] = await query<{ alunoId: string | null }>(`SELECT "alunoId" FROM utilizadores WHERE id = $1`, [userId]).catch(() => [{ alunoId: null }]);
        if (u?.alunoId) {
          const [pend] = await query<{ total: string; soma: string }>(`SELECT COUNT(*) as total, COALESCE(SUM(valor),0) as soma FROM pagamentos WHERE "alunoId" = $1 AND status = 'pendente'`, [u.alunoId]).catch(() => [{ total: '0', soma: '0' }]);
          if (Number(pend?.total) > 0) sugs.push({ text: `${pend?.total} propina(s) vencidas — ${Math.round(Number(pend?.soma)).toLocaleString('pt-PT')} AOA`, icon: 'warning-outline', urgent: true });
          const [falt] = await query<{ total: string }>(`SELECT COUNT(*) as total FROM presencas WHERE "alunoId" = $1 AND presente = false AND EXTRACT(MONTH FROM data) = $2 AND EXTRACT(YEAR FROM data) = $3`, [u.alunoId, mesAtual, anoAtual]).catch(() => [{ total: '0' }]);
          if (Number(falt?.total) > 0) sugs.push({ text: `${falt?.total} falta(s) este mês`, icon: 'calendar-outline' });
          sugs.push({ text: 'Ver as minhas notas actuais', icon: 'school-outline' });
        }
      }
      if (role === 'encarregado') {
        sugs.push({ text: 'Aproveitamento do educando', icon: 'school-outline' });
        sugs.push({ text: 'Propinas em atraso do educando', icon: 'card-outline' });
        sugs.push({ text: 'Faltas deste mês', icon: 'calendar-outline' });
      }
      if (role === 'financeiro') {
        const [pR] = await query<{ total: string }>(`SELECT COUNT(*) as total FROM pagamentos WHERE status = 'pendente'`, []).catch(() => [{ total: '0' }]);
        if (Number(pR?.total) > 0) sugs.push({ text: `${pR?.total} pagamentos pendentes`, icon: 'alert-circle-outline', urgent: true });
        sugs.push({ text: `Receita cobrada em ${mesAtual}/${anoAtual}`, icon: 'cash-outline' });
        sugs.push({ text: 'Top 5 devedores', icon: 'people-outline' });
      }
      if (role === 'secretaria' || role === 'chefe_secretaria') {
        const [pd] = await query<{ total: string }>(`SELECT COUNT(*) as total FROM solicitacoes_documentos WHERE status = 'pendente'`, []).catch(() => [{ total: '0' }]);
        if (Number(pd?.total) > 0) sugs.push({ text: `${pd?.total} documentos pendentes`, icon: 'document-outline', urgent: true });
        sugs.push({ text: 'Como fazer uma matrícula?', icon: 'add-circle-outline' });
        sugs.push({ text: 'Lista de alunos activos', icon: 'list-outline' });
      }
      if (role === 'rh') {
        const exp = await query<{ total: string }>(`SELECT COUNT(*) as total FROM funcionarios WHERE ativo = true AND "dataFimContrato" IS NOT NULL AND "dataFimContrato" <= NOW() + INTERVAL '30 days' AND "dataFimContrato" >= NOW()`, []).catch(() => [{ total: '0' }]);
        if (Number(exp[0]?.total) > 0) sugs.push({ text: `${exp[0]?.total} contrato(s) a expirar em 30 dias`, icon: 'time-outline', urgent: true });
        sugs.push({ text: 'Processar folha salarial do mês', icon: 'cash-outline' });
        sugs.push({ text: 'Relatório de presenças do pessoal', icon: 'bar-chart-outline' });
      }
      if (sugs.length === 0) sugs.push({ text: 'Como posso usar esta aplicação?', icon: 'help-circle-outline' });
      return res.json(sugs.slice(0, 5));
    } catch (err) {
      console.error('[ai-dynamic-suggestions]', err);
      return res.json([]);
    }
  });

