  app.post('/api/ai-report', requireAuth, async (req: Request, res: Response) => {
    const jwtUser = (req as any).jwtUser as { userId: string; role: string; email: string } | undefined;
    if (!jwtUser) return res.status(401).json({ error: 'Não autenticado' });
    if (!['ceo', 'pca', 'director', 'admin'].includes(jwtUser.role)) return res.status(403).json({ error: 'Acesso negado' });

    const geminiKey = process.env.GEMINI_API_KEY;
    if (!geminiKey) return res.status(503).json({ error: 'Serviço de IA não configurado. Adiciona GEMINI_API_KEY nos Secrets.' });

    const GEMINI_MODEL = 'gemini-2.5-flash';
    const GEMINI_URL = `https://generativelanguage.googleapis.com/v1beta/models/${GEMINI_MODEL}:generateContent?key=${geminiKey}`;

    const realtimeCtx = await fetchRealtimeContext(jwtUser.role, jwtUser.userId);
    const hoje = new Date().toLocaleDateString('pt-PT', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

    const reportBody = {
      system_instruction: { parts: [{ text: 'És um analista de dados especializado em gestão escolar em Angola. Geras relatórios executivos precisos e accionáveis com base em dados reais do sistema SIGA. Escreve em Português de Angola. Usa Markdown para formatação (negrito, listas, secções).' }] },
      contents: [{ role: 'user', parts: [{ text: `${realtimeCtx}\n\nData de hoje: ${hoje}\n\nCom base nos dados acima, gera um relatório executivo completo com:\n1. **Sumário Executivo** (2-3 frases)\n2. **Situação Académica** (alunos, turmas, professores, presenças)\n3. **Situação Financeira** (receitas, pendências, devedores)\n4. **Pontos de Atenção** (urgências identificadas nos dados)\n5. **Recomendações** (3 acções concretas baseadas nos dados)\n\nSê directo e objectivo. Cada secção máx. 4 linhas.` }] }],
      generationConfig: { maxOutputTokens: 1500, temperature: 0.4 },
    };

    let report = '';
    try {
      const r = await fetch(GEMINI_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(reportBody),
      });
      if (r.ok) {
        const d = await r.json() as any;
        report = d?.candidates?.[0]?.content?.parts?.[0]?.text ?? '';
      } else {
        const errBody = await r.text().catch(() => '');
        console.warn('[ai-report] Gemini HTTP', r.status, errBody.slice(0, 200));
      }
      if (!report) return res.status(502).json({ error: 'Não foi possível gerar o relatório.' });
      return res.json({ report, geradoEm: new Date().toISOString() });
    } catch (err) {
      console.error('[ai-report]', err);
      return res.status(500).json({ error: 'Erro interno.' });
    }
  });

