  // GET /api/protecao/status — estado do sistema de protecção
  app.get("/api/protecao/status", requireAuth, async (req: Request, res: Response) => {
    if (req.jwtUser?.role !== 'ceo') return json(res, 403, { error: 'Acesso restrito ao CEO.' });
    try {
      const { getProtectionStatus, generateFingerprint } = await import("./protection");
      const status = getProtectionStatus();
      const fp = generateFingerprint();
      json(res, 200, { ...status, fingerprintActual: fp });
    } catch (e) { json(res, 500, { error: (e as Error).message }); }
  });

  // GET /api/protecao/dominios — listar domínios autorizados
  app.get("/api/protecao/dominios", requireAuth, async (req: Request, res: Response) => {
    if (req.jwtUser?.role !== 'ceo') return json(res, 403, { error: 'Acesso restrito ao CEO.' });
    try {
      const rows = await query<{ dominiosAutorizados?: string[] | null }>(
        `SELECT "dominiosAutorizados" FROM public.config_geral LIMIT 1`, []
      );
      const dominios = rows[0]?.dominiosAutorizados ?? [];
      json(res, 200, { dominios: Array.isArray(dominios) ? dominios : [] });
    } catch (e) { json(res, 500, { error: (e as Error).message }); }
  });

  // POST /api/protecao/dominios — adicionar domínio autorizado
  app.post("/api/protecao/dominios", requireAuth, async (req: Request, res: Response) => {
    if (req.jwtUser?.role !== 'ceo') return json(res, 403, { error: 'Acesso restrito ao CEO.' });
    try {
      const b = requireBodyObject(req) as { dominio?: string };
      const dominio = String(b.dominio ?? '').toLowerCase().trim();
      if (!dominio || !/^[a-z0-9.-]+$/.test(dominio)) {
        return json(res, 400, { error: 'Domínio inválido. Use apenas letras, números, pontos e hífenes.' });
      }
      const { adicionarDominio } = await import("./protection");
      await adicionarDominio(dominio);
      json(res, 200, { ok: true, dominio });
    } catch (e) { json(res, 500, { error: (e as Error).message }); }
  });

  // DELETE /api/protecao/dominios/:dominio — remover domínio autorizado
  app.delete("/api/protecao/dominios/:dominio", requireAuth, async (req: Request, res: Response) => {
    if (req.jwtUser?.role !== 'ceo') return json(res, 403, { error: 'Acesso restrito ao CEO.' });
    try {
      const dominio = decodeURIComponent(req.params.dominio ?? '').toLowerCase().trim();
      const { removerDominio } = await import("./protection");
      await removerDominio(dominio);
      json(res, 200, { ok: true, dominio });
    } catch (e) { json(res, 500, { error: (e as Error).message }); }
  });

